/*
  Add CASA RPL(A) v1.2 syllabus course generated from Bendigo Flying Club shared DOCX syllabus folder.
  The numbered RPL(A) documents become course lessons; the summary/introduction documents provide metadata and exams.
*/

DO $$
DECLARE
  v_course_id uuid;
BEGIN
  DELETE FROM public.training_courses WHERE title = 'CASA RPL(A) v1.2';
  INSERT INTO public.training_courses (
    title, description, category, version, status, estimated_duration_hours,
    prerequisites, objectives, evaluation_criteria, tags, assessment_criteria,
    requires_student_acknowledgement, completion_endorsement_enabled,
    completion_endorsement_type, completion_endorsement_expiry_months,
    exam_requirements, last_updated
  ) VALUES (
    'CASA RPL(A) v1.2',
    'This syllabus describes flight training and assessment for the Recreational Pilot Licence - Aeroplane category rating and flight radio endorsement. It is based on the CASA RPL(A) v1.2 syllabus documents and includes general handling, circuit operations, emergency/abnormal procedures, solo consolidation, basic instrument flight and flight test readiness.',
    'CASA RPL(A)',
    '1.2',
    'published',
    30,
    ARRAY['Minimum age requirements apply before solo flight and licence application', 'Student should be proficient in English language']::text[],
    ARRAY['Safely exercise the privileges of the RPL(A) aeroplane category rating', 'Develop required Part 61 MOS practical flight competencies', 'Complete required theory examinations and language assessments', 'Demonstrate safe solo, circuit, training area, emergency, basic instrument and flight test readiness']::text[],
    ARRAY['CASA Part 61 MOS practical flight competency standards', 'Required performance standards in each lesson document', 'Instructor sign-off and student acknowledgement of lesson outcomes', 'Completion of required examinations and flight test recommendation']::text[],
    ARRAY['CASA', 'RPL(A)', 'Flight Radio', 'v1.2', 'Part 61 MOS']::text[],
    '[{"id": "casa-rpl-performance-standard", "name": "CASA RPL practical performance standard", "gradingSystem": "Pass or Fail", "passingGrade": "Pass"}, {"id": "casa-rpl-hf-nts", "name": "Human factors, NTS and airmanship", "gradingSystem": "Pass or Fail", "passingGrade": "Pass"}, {"id": "casa-rpl-knowledge", "name": "Pre-flight knowledge and theory readiness", "gradingSystem": "Pass or Fail", "passingGrade": "Pass"}]'::jsonb,
    true,
    true,
    'RPL(A) Aeroplane Category Rating',
    NULL,
    '[{"id": "pre-solo-exam", "name": "Pre-solo examination", "passMark": 70}, {"id": "pre-area-solo-exam", "name": "Pre-area solo examination", "passMark": 70}, {"id": "rpla-aeronautical-knowledge-exam", "name": "RPLA aeronautical knowledge examination", "passMark": 70}, {"id": "rpl-flight-radio-operator-exam", "name": "RPL flight radio operator examination", "passMark": 70}]'::jsonb,
    now()
  ) RETURNING id INTO v_course_id;

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    0,
    'Effects of Controls',
    'Introduction to manoeuvring the aeroplane on the ground and in flight Attitude flying Primary and secondary effect of controls Operation of ancillary controls Effect of power, slipstream, airspeed, undercarriage (if retractable), flap and trim',
    '<p><strong>Lesson overview</strong></p><ul><li>Introduction to manoeuvring the aeroplane on the ground and in flight Attitude flying Primary and secondary effect of controls Operation of ancillary controls Effect of power, slipstream, airspeed, undercarriage (if retractable), flap and trim</li></ul><ul><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: complete all required pre-flight administration documentation (required standard 3)</li><li>C2.2: Perform pre-flight inspection</li><li>C2.2: complete an internal and external check of the aircraft (required standard 3)</li><li>C2.2: ensure all aircraft locking and securing devices, covers and bungs are removed and stowed securely (required standard 3)</li><li>A1.1: Start and stop engine</li><li>A1.1: perform engine start and after start actions (required standard 3)</li><li>A1.1: perform engine shutdown and after shutdown actions (required standard 3)</li><li>A1.1: considers ground surface in relation to contamination and propeller care during engine start and stop activities (required standard 3)</li><li>A1.2: Taxi aeroplane</li><li>A1.2: comply with taxiway and other aerodrome markings, right-of-way rules and ATC or marshalling instructions when applicable (required standard 3)</li><li>A1.2: maintain safe taxi speed and control of the aircraft (required standard 3)</li><li>A1.2: maintain safe spacing from other aircraft, obstructions, and persons (required standard 3)</li><li>A1.2: taxi the aeroplane along the centre of the taxiway (required standard 3)</li><li>A1.2: avoid causing a hazard to other aircraft, objects or persons (required standard 3)</li><li>A1.2: correctly manage the engine during taxi manoeuvres (required standard 3)</li><li>NTS1.1: Maintain effective lookout</li><li>NTS1.1: maintain traffic separation using a systematic visual scan technique at a rate determined by traffic density, visibility and terrain (required standard 3)</li><li>C2.3: Post-flight actions and procedures</li><li>C2.3: shut down aircraft (required standard 3)</li><li>C2.3: conduct post-flight inspection and secure the aircraft (if applicable) (required standard 3)</li><li>C2.3: complete all required post-flight administration documentation (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 1.0 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 1.0 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Effects of Controls Planes of movement; pitch, roll &amp; yaw Control surfaces Primary effect of controls Secondary effect of controls Operation of ancillary controls Effect of power, slipstream and airspeed Operation and effect of undercarriage (if retractable),operation and effect of flap Operation and effect of trimming control(s) Application in flight</li><li>Underpinning knowledge Identify grade of fuel, verify fuel quantity (pre-flight inspection) [C4 4(b)&amp;(c)] Typical single-engine aeroplane systems [A4 4(a)], carburettor icing [A1 4(c)] Ground surface and propeller care considerations [A1 4(l)] Primary effects of controls [A3 4(a)] Secondary effects of controls [A3 4(b)]</li><li>HF &amp; NTS Principles of ‘see and avoid’ Visual scan technique - use of clock code Hand over/take over technique (e.g. ‘I have control - you have control’) Control technique</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-01',
    'RPL(A)1',
    'Effects of Controls',
    'flight',
    60,
    'Introduce',
    ARRAY['Introduction to manoeuvring the aeroplane on the ground and in flight', 'Attitude flying', 'Primary and secondary effect of controls', 'Operation of ancillary controls', 'Effect of power, slipstream, airspeed, undercarriage (if retractable), flap and trim']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>01_RPL(A) Effects of Controls.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    1,
    'Straight & Level',
    'Establish and maintain straight and level flight Straight flight - reference point/heading, wings level, aeroplane in balance Level flight - attitude, trim Power + attitude+ configuration = performance Straight & level at various airspeeds, power settings and configurations: normal, fast, slow & precautionary (flaps) cruise',
    '<p><strong>Lesson overview</strong></p><ul><li>Establish and maintain straight and level flight Straight flight - reference point/heading, wings level, aeroplane in balance Level flight - attitude, trim Power + attitude+ configuration = performance Straight &amp; level at various airspeeds, power settings and configurations: normal, fast, slow &amp; precautionary (flaps) cruise</li></ul><ul><li>C1.1: Communicating face-to-face</li><li>C1.1: pronounces words clearly, using an accent that does not cause difficulties in understanding (required standard 3)</li><li>C1.1: conveys information in clearly structured sentences without confusion or ambiguity (required standard 3)</li><li>C1.1: uses an extensive vocabulary to accurately communicate on general and technical topics, without excessive use of jargon, slang or colloquial language (required standard 3)</li><li>C1.1: speaks fluently without long pauses, repetition or excessive false starts (required standard 3)</li><li>C1.1: responds to communications with actions that demonstrate that the information has been received and understood (required standard 3)</li><li>C1.1: exchanges information clearly in a variety of situations with both expert and non-expert English speakers while giving and receiving timely and appropriate responses (required standard 3)</li><li>C1.1: uses appropriate techniques to validate communications (required standard 3)</li><li>A3.2: Maintain straight and level flight</li><li>A3.2: operate and monitor all aircraft systems during straight and level flight manoeuvres (required standard 3)</li><li>A3.2: adjust altimeter subscale according to applicable settings (required standard 3)</li><li>A3.2: identify and avoid terrain and traffic (required standard 3)</li><li>A3.2: for the following straight and level manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.2: at slow speed (required standard 3)</li><li>A3.2: at normal cruise (required standard 3)</li><li>A3.2: at high-speed cruise (required standard 3)</li><li>A3.2: during acceleration and deceleration (required standard 3)</li><li>A3.2: with flaps selected (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 1.0 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 1.0 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Straight &amp; Level Aerodynamic forces acting on the aeroplane; lift, weight, thrust, drag Generation of lift Stability Attitude flying Power + attitude +configuration = performance Operation of controls and technique for maintaining straight flight &amp; level flight Instrument indications Cruise configurations Application in flight</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Typical single-engine aeroplane systems [[A1 4(a), A3 4(d)] Fuel requirements for day VFR flight operation [C2 4(b), C4 4(a)]</li><li>HF &amp; NTS Principles of ‘see and avoid’ Visual limitations Visual scan technique - use of clock code Hand over/take over technique (e.g. ‘I have control - you have control’) Control technique</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-02',
    'RPL(A)2',
    'Straight & Level',
    'flight',
    60,
    'Introduce',
    ARRAY['Establish and maintain straight and level flight', 'Straight flight - reference point/heading, wings level, aeroplane in balance', 'Level flight - attitude, trim', 'Power + attitude+ configuration = performance']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>02_RPL(A) Straight &amp; Level.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    2,
    'Climbing & Descending',
    'Establish and maintain various types of climb and descent Entry and levelling off sequence Normal (cruise), best rate (Vy) and best angle (Vx) climbs Effect of undercarriage (if retractable), flap and power on the climb Cruise, glide and approach descents Effect of wind, undercarriage (if retractable), flap and power on the glide',
    '<p><strong>Lesson overview</strong></p><ul><li>Establish and maintain various types of climb and descent Entry and levelling off sequence Normal (cruise), best rate (Vy) and best angle (Vx) climbs Effect of undercarriage (if retractable), flap and power on the climb Cruise, glide and approach descents Effect of wind, undercarriage (if retractable), flap and power on the glide</li></ul><ul><li>C4.1: Plan fuel requirements</li><li>C4.1: conduct transmission and receipt of radio communications using appropriate procedures and phraseology (required standard 3)</li><li>C4.1: determine the total fuel required for the flight (required standard 3)</li><li>C4.2: Manage fuel system</li><li>C4.2: verify fuel quantity on-board aircraft prior to flight using two independent methods (required standard 3)</li><li>C4.2: ensure the fuel caps are secured (required standard 3)</li><li>C4.2: perform fuel quality check prior to flight (required standard 3)</li><li>C4.2: ensure fuel drain cocks are closed (required standard 3)</li><li>A3.1: Climb aeroplane</li><li>A3.1: operate and monitor all aircraft systems when commencing, during, and completing a climbing flight manoeuvre (required standard 3)</li><li>A3.1: adjust altimeter subscale according to applicable settings (required standard 3)</li><li>A3.1: identify and avoid terrain and traffic (required standard 3)</li><li>A3.1: for the following climbing manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.1: cruise climb (required standard 3)</li><li>A3.1: best angle climb (required standard 3)</li><li>A3.1: best rate climb (required standard 3)</li><li>A3.1: anticipate level-off altitude and achieve straight and level flight (required standard 3)</li><li>A3.3: Descend aeroplane</li><li>A3.3: operate and monitor all aircraft systems during descending flight manoeuvres (required standard 3)</li><li>A3.3: for the following descending manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.3: glide (required standard 3)</li><li>A3.3: powered (required standard 3)</li><li>A3.3: approach configuration descent (flap and undercarriage) (required standard 3)</li><li>A3.3: anticipate level-off altitude and achieve straight and level flight (required standard 3)</li><li>NTS1.1: Maintain effective lookout</li><li>NTS1.1: perform airspace-cleared procedure before commencing any manoeuvre (required standard 3)</li><li>NTS1.4: Set priorities and manage tasks</li><li>NTS1.4: organise workload and priorities to ensure optimum outcome of the flight (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Climbing and Descending Aerodynamic forces acting on the aeroplane during climb and descent Attitude flying Power + attitude + configuration = performance Maintenance of straight flight during climb and descent Entry and levelling off sequence (e.g. Power, Attitude, Trim - Attitude, Power, Trim) Normal, best rate (Vy) and best angle (Vx) climbs Climb performance - effect of power, wind and aeroplane configuration Glide performance - best glide speed, effect of aeroplane configuration, weight and wind Descending at various airspeeds, effect of power &amp; flap Instrument indications Application in flight</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Typical aeroplane performance characteristics &amp; the effect of local weather conditions [A1 4(e)] Factors affecting take-off and initial climb performance [A2 4(b)] Aeroplane performance [A3 4(e)] Engine considerations during prolonged climbing and descending [A3 4(l)] Aircraft performance in a glide (straight and turning) [A6 4(i)]</li><li>HF &amp; NTS Fitness for flight Use of checklists [NTS2 4(h)] Principles of ‘see and avoid’ Visual limitations Visual scan technique - use of clock code Lookout technique prior to and during climb and descent Monitor engine temperature and pressure Hand over/take over technique (e.g. ‘I have control - you have control’) Control technique</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-03',
    'RPL(A)3',
    'Climbing & Descending',
    'flight',
    60,
    'Introduce',
    ARRAY['Establish and maintain various types of climb and descent', 'Entry and levelling off sequence', 'Normal (cruise), best rate (Vy) and best angle (Vx) climbs', 'Effect of undercarriage (if retractable), flap and power on the climb Cruise, glide and approach descents', 'Effect of wind, undercarriage (if retractable), flap and power on the glide']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>03_RPL(A) Climbing &amp; Descending.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    3,
    'Turning',
    'Adverse yaw demonstration Medium level turns Climbing turns Descending turns (glide and powered) Introduction to spiral dive - recognition and recovery (instructor demonstration only) Refuelling Assess: Communicating face-to-face',
    '<p><strong>Lesson overview</strong></p><ul><li>Adverse yaw demonstration Medium level turns Climbing turns Descending turns (glide and powered) Introduction to spiral dive - recognition and recovery (instructor demonstration only) Refuelling Assess: Communicating face-to-face</li></ul><ul><li>C1.1: Communicating face-to-face</li><li>C1.1: pronounces words clearly, using an accent that does not cause difficulties in understanding (required standard 2)</li><li>C1.1: conveys information in clearly structured sentences without confusion or ambiguity (required standard 2)</li><li>C1.1: uses an extensive vocabulary to accurately communicate on general and technical topics, without excessive use of jargon, slang or colloquial language (required standard 2)</li><li>C1.1: speaks fluently without long pauses, repetition or excessive false starts (required standard 2)</li><li>C1.1: responds to communications with actions that demonstrate that the information has been received and understood (required standard 2)</li><li>C1.1: exchanges information clearly in a variety of situations with both expert and non-expert English speakers while giving and receiving timely and appropriate responses (required standard 2)</li><li>C1.1: uses appropriate techniques to validate communications (required standard 2)</li><li>C1.2: Operational communication using an aeronautical radio</li><li>C1.2: apply the phonetic alphabet (required standard 3)</li><li>C1.2: transmit numbers (required standard 3)</li><li>C1.2: make appropriate transmissions using standard aviation phraseology (required standard 3)</li><li>C1.2: use plain English effectively when standard phraseology is inadequate (required standard 3)</li><li>C1.2: receive appropriate responses to transmissions (required standard 3)</li><li>C3.1: Operate radio equipment</li><li>C3.1: conduct transmission and receipt of radio communications using appropriate procedures and phraseology (required standard 3)</li><li>C4.3: Refuel aircraft</li><li>C4.3: identify the correct type of fuel to be used (required standard 3)</li><li>C4.3: ensure aircraft is earthed prior to refuelling and defueling operations (required standard 3)</li><li>C4.3: correctly load and unload fuel (required standard 3)</li><li>C4.3: ensure required fuel quantity is loaded (required standard 3)</li><li>C4.3: ensure fuel caps are closed and secured after fuelling operations (required standard 3)</li><li>C4.3: perform fuel quality checks (required standard 3)</li><li>C3.3: Operate transponder</li><li>C3.3: operate a transponder during normal, abnormal and emergency operations (normal operations) (required standard 3)</li><li>A3.4: Turn aeroplane</li><li>A3.4: operate and monitor all aircraft systems during turning flight manoeuvres (required standard 3)</li><li>A3.4: for the following turning manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.4: (i) level turns (required standard 3)</li><li>A3.4: (ii) climbing turns (required standard 3)</li><li>A3.4: (iii) powered descending turns (required standard 3)</li><li>A3.4: (iv) gliding descending turns (required standard 3)</li><li>A3.4: complete turn manoeuvre on a nominated heading or geographical feature (required standard 3)</li><li>A3.4: turn aeroplane at varying rates to achieve specified tracks (required standard 3)</li><li>A3.4: manoeuvre aeroplane over specified tracks or geographical features (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Turning Aerodynamic forces acting on the aeroplane during a turn Adverse yaw Overbank/underbank tendency Attitude flying Medium level turns, climbing turns, descending turns Spiral dive introduction - causes, symptoms, recognition and recovery technique Instrument indications Application in flight</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Basic radiotelephony phraseology and common aviation terminology [C1 4(a)&amp;(b)] Phonetic alphabet [C3 4(a)] Aeronautical radio system components [C3 4(c)] Refuelling procedures, precautions and safety requirements [C4 4(d)-(g)] Meaning of aerodrome markings, signals and local procedures [A1 4(k)]</li><li>HF &amp; NTS Fitness for flight Principles of ‘see and avoid’ Visual limitations Visual scan technique - use of clock code Lookout technique prior and during turning Work cycle (e.g. lookout, attitude, performance-LAP) Hand over/take over technique (e.g. ‘I have control - you have control’) Control technique</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-04',
    'RPL(A)4',
    'Turning',
    'flight',
    60,
    'Introduce',
    ARRAY['Adverse yaw demonstration', 'Medium level turns', 'Climbing turns', 'Descending turns (glide and powered)', 'Introduction to spiral dive - recognition and recovery (instructor demonstration only)', 'Refuelling Assess:', 'Communicating face-to-face']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>04_RPL(A) Turning.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    4,
    'Stalling',
    'Checklist procedures (e.g. HASELL) Slow flight Symptoms and recognition of an imminent stall Symptoms and recognition of a fully developed stall Recovery technique Effect of power on recovery Effect of power, undercarriage (if retractable) and flap on the stall Landing configuration stall Wing drop recovery Incipient spin recognition and recovery (instructor demonstration only) Engine start and shutdown malfunctions and emergencies Assess: straight and level control aeroplane at slow speed stalling (from straight and level, approach configuration) communicating face-to-face',
    '<p><strong>Lesson overview</strong></p><ul><li>Checklist procedures (e.g. HASELL) Slow flight Symptoms and recognition of an imminent stall Symptoms and recognition of a fully developed stall Recovery technique Effect of power on recovery Effect of power, undercarriage (if retractable) and flap on the stall Landing configuration stall Wing drop recovery Incipient spin recognition and recovery (instructor demonstration only) Engine start and shutdown malfunctions and emergencies Assess: straight and level control aeroplane at slow speed stalling (from straight and level, approach configuration) communicating face-to-face</li></ul><ul><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: obtain, interpret and apply information contained in the required pre-flight operational documentation, including the following:</li><li>C2.1: maintenance release (required standard 3)</li><li>C2.1: local observations (required standard 3)</li><li>C2.1: identify special aerodrome procedures (required standard 3)</li><li>C2.1: determine the suitability of the current weather conditions for the proposed flight (required standard 3)</li><li>C2.1: determine whether the aircraft is serviceable for the proposed flight (required standard 3)</li><li>A1.1: Start and stop engine</li><li>A1.1: manage engine start and shutdown malfunctions and emergencies (e.g. flooded start, inoperative magneto after start, inoperative magneto or live magneto on shutdown) (required standard 3)</li><li>C1.1: Communicating face-to-face</li><li>C2.2: Perform pre-flight inspection</li><li>C2.2: identify and secure equipment and documentation that is required for the flight (required standard 3)</li><li>C2.2: identify all defects or damage to the aircraft (required standard 3)</li><li>A3.2: Maintain straight and level flight</li><li>A3.2: operate and monitor all aircraft systems during straight and level flight manoeuvres (required standard 2)</li><li>A3.2: adjust altimeter subscale according to applicable settings (required standard 2)</li><li>A3.2: identify and avoid terrain and traffic (required standard 2)</li><li>A3.2: for the following straight and level manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.2: at slow speed (required standard 2)</li><li>A3.2: at normal cruise (required standard 2)</li><li>A3.2: at high-speed cruise (required standard 2)</li><li>A3.2: during acceleration and deceleration (required standard 2)</li><li>A3.2: with flaps selected (required standard 2)</li><li>A3.5: Control aeroplane at slow speeds</li><li>A3.5: complete pre-manoeuvre checks (required standard 2)</li><li>A3.5: operate and monitor all aircraft systems when operating the aeroplane at slow speed (required standard 2)</li><li>A3.5: for the following climbing manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.5: minimum approach speed with flaps retracted (required standard 2)</li><li>A3.5: minimum approach speed in approach configuration (required standard 2)</li><li>A3.5: observe audible and visual stall warnings and recover aeroplane to controlled flight (required standard 2)</li><li>A3.5: recognise and respond positively to reduced effectiveness of controls during slow flight manoeuvres (required standard 2)</li><li>A3.5: transition from slow speed configuration using take-off power to achieve nominated speed in excess of 1.5 Vs without loss of height (required standard 2)</li><li>A5.1: Enter and recover from stall</li><li>A5.1: perform pre-manoeuvre checks for stalling (required standard 2)</li><li>A5.1: recognise stall signs and symptoms (required standard 2)</li><li>A5.1: control the aeroplane by applying the required pitch, roll and yaw inputs as appropriate in a smooth, coordinated manner, trim aeroplane accurately to enter and recover from the following manoeuvres:</li><li>A5.1: incipient stall (required standard 2)</li><li>A5.1: stall without power applied (required standard 2)</li><li>A5.1: stall under the following conditions:</li><li>A5.1: (A) straight and level flight (required standard 2)</li><li>A5.1: (D) approach to land configuration (required standard 2)</li><li>A5.1: perform stall recovery as follows:</li><li>A5.1: positively reduce angle of attack (required standard 2)</li><li>A5.1: use power available and excess height to increase the aircraft energy state (required standard 2)</li><li>A5.1: minimise height loss for simulated low altitude condition (required standard 2)</li><li>A5.1: re-establish desired flight path and aircraft control (required standard 2)</li><li>A5.2: Recover from incipient spin (instructor demonstration only)</li><li>A5.2: perform pre-manoeuvre checks for an incipient spin (required standard 3)</li><li>A5.2: recognise an incipient spin (required standard 3)</li><li>A5.2: use the aeroplane&#x27;s attitude and power controls to execute an incipient spin manoeuvre from the following flight conditions and, using correct recovery technique, regain straight and level flight with height loss commensurate with the available altitude (simulated ground base height may be set):</li><li>A5.2: straight and level flight</li><li>A6.6: Recover from unusual flight attitudes</li><li>A6.6: identify nose-high unusual attitude flight condition (required standard 3)</li><li>A6.6: recover from nose-high unusual attitudes by adjusting pitch, bank and power to resume controlled and balanced flight (required standard 3)</li><li>A6.6: apply controlled corrective action while maintaining aircraft performance within limits (required standard 3)</li><li>C4.2: Manage fuel system</li><li>C4.2: monitor fuel usage during the flight (required standard 3)</li><li>C4.2: perform fuel tank changes correctly (required standard 3)</li><li>C4.2: maintain fuel load within aircraft limits (required standard 3)</li><li>C4.2: operate fuel pumps and engine controls correctly (required standard 3)</li><li>NTS1.2: Maintain situational awareness</li><li>NTS1.2: monitor all aircraft systems using a systematic scan technique (required standard 3)</li><li>NTS1.2: collect information to facilitate ongoing system management (required standard 3)</li><li>NTS1.2: monitor flight environment for deviations from planned operations (required standard 3)</li><li>NTS1.2: collect flight environment information to update planned operations (required standard 3)</li><li>NTS2.1: Recognise and manage threats</li><li>NTS2.1: identify relevant environmental or operational threats that are likely to affect the safety of the flight (required standard 3)</li><li>NTS2.1: monitor and assess flight progress to ensure a safe outcome, or modify actions when a safe outcome is not assured (required standard 3)</li><li>NTS2.2: Recognise and manage errors</li><li>NTS2.2: apply checklists and standard operating procedures to prevent aircraft handling, procedural or communication errors (required standard 3)</li><li>NTS2.2: identify committed errors before safety is affected or the aircraft enters an undesired state (required standard 3)</li><li>NTS2.2: implement countermeasures to prevent errors or take action in the time available to correct errors before the aircraft enters an undesired state (required standard 3)</li><li>NTS2.3: Recognise and manage undesired aircraft state</li><li>NTS2.3: recognise an undesired aircraft state (required standard 3)</li><li>NTS2.3: prioritise tasks to ensure an undesired aircraft state is managed effectively (required standard 3)</li><li>NTS2.3: apply corrective actions to recover an undesired aircraft state in a safe and timely manner (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Stalling Stall aerodynamics Stall avoidance Control effectiveness at slow speed Symptoms and recognition of an imminent stall Stall warning device Symptoms and recognition of a fully developed stall Recovery from an imminent stall Recovery from fully developed stall Control technique Effect of power on recovery Factors affecting stall speed (weight, power, flap and/or slat position, dynamic loading, ice or damage to wings) Instrument indications Application in flight and checklist procedures (e.g. HASELL checks)</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Standard operating procedures for the category, and class or type of aircraft and the operator [C2 4(a)] Engine start procedures - cold start, flooded start Difference between normally aspirated and fuel-injected systems [A1 4(b)] Cause and effect of fuel vaporisation [A1 4(d)] Stall warning devices [A3 4(c)] Relationship between AOB, LF &amp; stall speed [A3 4(i)] Relationship between induced drag and operating at low speed [A3 4(j)] Aerodynamic and aeroplane operational considerations related to slow flight, stalling, spinning &amp; upset aeroplane states [A5 4(b)], including, but not limited to: symptoms of approach to stall and throughout the stall manoeuvre until recovery relationship between angle of attack and stall effects of weight, ‘g’ force and angle of attack dangers of unbalanced flight principles relating to the position of the elevator control and the point of stall priority given to reduce angle of attack during stall manoeuvres loss of height is considered in relation to available height and energy state the technique of converting excess height to speed the technique of converting excess speed to height symmetrical and rolling ‘g’ force limitations higher stall speeds when the aeroplane is turning effects on fuel, pitot and flap systems</li><li>HF &amp; NTS Task management [NTS1 4(b)] Use of checklists and standard operating procedures to prevent errors [NTS2 4(h)] Application of situational awareness to identify real or potential threats [NTS2 4(c)] Developing and implementing plans of action to remove and mitigate threats and errors [NTS2 4(d)] Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] Initial reaction to undesired aeroplane state (‘startle effect’), importance of recognition skills and well-rehearsed responses How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-05',
    'RPL(A)5',
    'Stalling',
    'flight',
    60,
    'Introduce',
    ARRAY['Checklist procedures (e.g. HASELL)', 'Slow flight', 'Symptoms and recognition of an imminent stall', 'Symptoms and recognition of a fully developed stall', 'Recovery technique', 'Effect of power on recovery', 'Effect of power, undercarriage (if retractable) and flap on the stall', 'Landing configuration stall']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>05_RPL(A) Stalling.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    5,
    'Circuit Introduction',
    'Circuit introduction: normal take-off standard circuit normal approach normal landing Assess: straight and level control aeroplane at slow speed - training area stalling (from straight and level, approach configuration) - training area post-flight actions and procedures',
    '<p><strong>Lesson overview</strong></p><ul><li>Circuit introduction: normal take-off standard circuit normal approach normal landing Assess: straight and level control aeroplane at slow speed - training area stalling (from straight and level, approach configuration) - training area post-flight actions and procedures</li></ul><ul><li>A1.2: Taxi aeroplane</li><li>A1.2: perform applicable taxi checks, including the following:</li><li>A1.2: brakes and steering function normally and take appropriate action in the event of a malfunction (required standard 3)</li><li>A1.2: altimeter setting (required standard 3)</li><li>A1.2: correct handling techniques are applied to take into account wind from all four quadrants (required standard 3)</li><li>A2.1: Carry out pre take-off procedures</li><li>A2.1: correctly identify critical airspeeds, configurations, and emergency and abnormal procedures for normal and crosswind take-offs (required standard 3)</li><li>A2.1: work out a plan of action, in advance, to ensure the safest outcome in the event of abnormal operations (required standard 3)</li><li>A2.1: verify and correctly apply correction for the existing wind component to the take-off performance (required standard 3)</li><li>A2.1: perform all pre take-off and line-up checks required by the aircraft checklist (required standard 3)</li><li>A2.1: ensure approach path is clear of conflicting traffic and other hazards before lining up for take-off (required standard 3)</li><li>A2.1: align the aeroplane on the runway centreline (required standard 3)</li><li>A2.2: Take off aeroplane</li><li>A2.2: apply the controls correctly to maintain longitudinal alignment on the centreline of the runway, if appropriate, prior to initiating and during the take-off (required standard 3)</li><li>A2.2: adjust the power controls taking into account the existing conditions (required standard 3)</li><li>A2.2: monitor power controls, settings, and instruments during take-off to ensure all predetermined parameters are achieved and maintained (required standard 3)</li><li>A2.2: adjust the controls to attain the desired pitch attitude at the predetermined airspeed to attain the desired performance (required standard 3)</li><li>A2.2: perform the take-off applying the required pitch, roll and yaw inputs as appropriate in a smooth, coordinated manner (required standard 3)</li><li>A2.2: trim the aeroplane accurately (required standard 3)</li><li>A2.2: perform gear and flap retractions, power adjustments (as applicable) and other required pilot-related activities (required standard 3)</li><li>A2.2: maintain flight path along the runway extended centreline (required standard 3)</li><li>A2.2: apply the applicable noise abatement and wake turbulence avoidance procedures (required standard 3)</li><li>A2.4: Carry out after take-off procedures</li><li>A2.4: perform after take-off checklist (required standard 3)</li><li>A2.4: maintain the appropriate climb segment at the nominated heading and airspeed (required standard 3)</li><li>A2.4: manoeuvre according to local and standard procedures (required standard 3)</li><li>A2.4: maintain traffic separation (required standard 3)</li><li>C1.2: Operational communication using an aeronautical radio</li><li>C1.2: maintain effective communication with others on operational matters (required standard 3)</li><li>C1.2: respond to transmissions and take appropriate action (required standard 3)</li><li>C1.2: recognise and manage communication errors and misunderstandings effectively (required standard 3)</li><li>C1.2: seek clarification in the time available if a message is unclear or uncertainty exists (required standard 3)</li><li>C1.2: react appropriately to a variety of regional accents (required standard 3)</li><li>C3.1: Operate radio equipment</li><li>C3.1: maintain a listening watch and respond appropriately to applicable transmissions (required standard 3)</li><li>A3.2: Maintain straight and level flight</li><li>A3.5: Control aeroplane at slow speeds</li><li>A5.1: Enter and recover from stall</li><li>A3.6: Perform circuits and approaches</li><li>A3.6: operate and monitor all aircraft systems when operating the aeroplane in the circuit (required standard 3)</li><li>A3.6: in accordance with specific local procedures, safely perform a full circuit pattern (5 legs) by balancing and trimming the aeroplane accurately while applying smooth, coordinated control inputs to achieve the required flight tolerances specified for the flight path flown during traffic pattern manoeuvres as follows:</li><li>A3.6: track upwind along extended centreline to 500 ft (required standard 3)</li><li>A3.6: establish and maintain crosswind leg tracking 90° to the runway (required standard 3)</li><li>A3.6: establish and maintain downwind leg tracking parallel to, and at a specified distance from, the runway at circuit height (required standard 3)</li><li>A3.6: establish base leg tracking 90° to the runway at a specified distance from the runway threshold (required standard 3)</li><li>A3.6: perform checks as required throughout circuit (required standard 3)</li><li>A3.6: establish the approach and landing configuration appropriate for the runway and meteorological conditions, and adjust the power plant controls as required for the following:</li><li>A3.6: commence and control approach descent path (required standard 3)</li><li>A3.6: adjust descent commencement point to take account of extended downwind leg or traffic adjustments (required standard 3)</li><li>A3.6: align and maintain aircraft on final approach flight path with specified or appropriate runway (required standard 3)</li><li>A3.6: set and maintain approach configuration not below 500 ft AGL (required standard 3)</li><li>A3.6: identify and maintain the nominated aiming point (required standard 3)</li><li>A3.6: maintain a stabilised approach angle at the nominated airspeed not less than 1.3Vs to the round-out height (required standard 3)</li><li>A3.6: verify existing wind conditions, make proper correction for drift, and maintain a precise ground track (required standard 3)</li><li>A3.6: apply speed allowances for wind gusts (required standard 3)</li><li>A3.6: configure aeroplane for landing (required standard 3)</li><li>A3.6: maintain aircraft separation and position in the circuit with reference to other aircraft traffic in the circuit area (required standard 3)</li><li>NTS1.1: Maintain effective lookout</li><li>NTS1.1: maintain radio listening watch and interpret transmissions to determine traffic location and intentions (required standard 3)</li><li>NTS1.4: Set priorities and manage tasks</li><li>NTS1.4: plan events and tasks to occur sequentially (required standard 3)</li><li>NTS1.4: anticipate events and tasks to ensure sufficient opportunity for completion (required standard 3)</li><li>A4.1: Land aeroplane</li><li>A4.1: maintain a constant landing position aim point (required standard 3)</li><li>A4.1: achieve a smooth, positively-controlled transition from final approach to touchdown, including the following:</li><li>A4.1: control ballooning during flare (required standard 3)</li><li>A4.1: touchdown at a controlled rate of descent, in the specified touchdown zone within tolerances (required standard 3)</li><li>A4.1: control bouncing after touchdown (required standard 3)</li><li>A4.1: touch down aligned with the centreline within tolerances (required standard 3)</li><li>A4.1: ensure separation is maintained (required standard 3)</li><li>A4.1: maintain positive directional control and crosswind correction during the after-landing roll (required standard 3)</li><li>A4.1: use drag and braking devices, as applicable, in such a manner to bring the aeroplane to a safe stop (required standard 3)</li><li>A4.1: complete the applicable after-landing checklist items in a timely manner (required standard 3)</li><li>C2.3: Post-flight actions and procedures</li><li>C2.3: shut down aircraft (required standard 2)</li><li>C2.3: conduct post-flight inspection and secure the aircraft (if applicable) (required standard 2)</li><li>C2.3: complete all required post-flight administration documentation (required standard 2)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Circuit introduction Circuit pattern Benefits of take-off and landing into wind Take-off technique Local aerodrome circuit procedures Aeroplane operating procedures and checklists Traffic management Interpretation of windsock indications - wind speed and direction Approach technique, judgement of aeroplane approach profile and regaining correct approach path Landing technique Procedures and cautions during touch and go</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Local aerodrome requirements [C2 4(f)], Local area operating procedures [A3 4(p)] (circuit area procedures) Documented radio procedures relevant to the VFR [C3 4(b)] Actions to be taken in the event of a brake, tyre or steering failure [A1 4(m)]</li><li>HF &amp; NTS Effective communication under normal circumstances [NTS1 4(a)] Application of situational awareness to identify real or potential environmental or operational threats to flight safety [NTS2 4(c)] Use of checklists and standard operating procedures to prevent errors [NTS2 4(h)] Task management, organise workload [NTS2 4(i),(i)-(v)] Visual scan technique - use of clock code, importance of lookout and identification of traffic Traffic management - speed control, circuit pattern adjustments Hand over/take over technique (e.g. ‘I have control - you have control’) Control technique</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-06',
    'RPL(A)6',
    'Circuit Introduction',
    'flight',
    60,
    'Introduce',
    ARRAY['Circuit introduction: normal take-off standard circuit normal approach normal landing Assess: straight and level control']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>06_RPL(A) Circuit Introduction.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    6,
    'Circuits',
    'Revise and consolidate circuits Introduce procedure in the event of radio failure within the circuit Assess: maintain effective lookout post-flight actions and procedures',
    '<p><strong>Lesson overview</strong></p><ul><li>Revise and consolidate circuits Introduce procedure in the event of radio failure within the circuit Assess: maintain effective lookout post-flight actions and procedures</li></ul><ul><li>C3.1: Operate radio equipment</li><li>C3.1: confirm serviceability of radio equipment (required standard 3)</li><li>C3.2: Manage R/T equipment malfunctions</li><li>C3.2: perform radio failure procedures (required standard 3)</li><li>C3.2: use fault finding procedures and perform corrective actions (required standard 3)</li><li>NTS1.1: Maintain effective lookout</li><li>NTS1.1: maintain traffic separation using a systematic visual scan technique at a rate determined by traffic density, visibility and terrain (required standard 2)</li><li>NTS1.1: maintain radio listening watch and interpret transmissions to determine traffic location and intentions (required standard 2)</li><li>NTS1.1: perform airspace-cleared procedure before commencing any manoeuvre (required standard 2)</li><li>C2.3: Post-flight actions and procedures</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Circuits Revise normal circuit operations as required Radio failure fault finding procedures Procedure to be followed in the event of a radio failure within the circuit</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Light signals including interpretation and actions required [C3 4(f)]</li><li>HF &amp; NTS Effective communication under normal circumstances [NTS1 4(a)] Application of situational awareness to identify real or potential threats [NTS2 4(c)] Task management, organise workload [NTS2 4(i),(i)-(v)] Visual scan technique - use of clock code, identification of traffic Traffic management - speed control, circuit pattern adjustments</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-07',
    'RPL(A)7',
    'Circuits',
    'flight',
    60,
    'Introduce',
    ARRAY['Revise and consolidate circuits']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>07_RPL(A) Circuits.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    7,
    'Circuits - Flapless & Missed Approach',
    'Circuit consolidation Flapless approach and landings Missed approach procedure Missed landing recovery Assess: maintain effective lookout',
    '<p><strong>Lesson overview</strong></p><ul><li>Circuit consolidation Flapless approach and landings Missed approach procedure Missed landing recovery Assess: maintain effective lookout</li></ul><ul><li>NTS1.1: Maintain effective lookout</li><li>NTS1.3: Assess situations and make decisions</li><li>NTS1.3: identify problems (required standard 3)</li><li>NTS1.3: analyse problems (required standard 3)</li><li>NTS1.3: identify solutions (required standard 3)</li><li>NTS1.3: assess solutions and risks (required standard 3)</li><li>NTS1.3: decide on a course of action (required standard 3)</li><li>NTS1.3: communicate plans of action (if appropriate) (required standard 3)</li><li>NTS1.3: allocate tasks for action (if appropriate) (required standard 3)</li><li>NTS1.3: take actions to achieve optimum outcomes for the operation (required standard 3)</li><li>NTS1.3: monitor progress against plan (required standard 3)</li><li>NTS1.3: re-evaluate plan to achieve optimum outcomes (required standard 3)</li><li>NTS2.1: Recognise and manage threats</li><li>NTS2.1: identify when competing priorities and demands may represent a threat to the safety of the flight (required standard 3)</li><li>NTS2.1: develop and implement countermeasures to manage threats (required standard 3)</li><li>A4.3: Conduct a missed approach</li><li>A4.3: recognise the conditions when a missed approach should be executed (required standard 3)</li><li>A4.3: make the decision to execute a missed approach when it is safe to do so (required standard 3)</li><li>A4.3: make a smooth, positively-controlled transition from approach to missed approach, including the following:</li><li>A4.3: select power, attitude and configuration to safely control aeroplane (required standard 3)</li><li>A4.3: manoeuvre aeroplane clear of the ground and conduct after take-off procedures (required standard 3)</li><li>A4.3: make allowance for wind velocity during go-around (required standard 3)</li><li>A4.3: avoid wake turbulence (required standard 3)</li><li>A4.4: Perform recovery from missed landing</li><li>A4.4: recognise when a missed landing is occurring and when it is appropriate to take recovery action (required standard 3)</li><li>A4.4: make the decision to execute recovery from a missed landing only when it is safe to do so (required standard 3)</li><li>A4.4: make a smooth, positively-controlled transition from a missed landing to missed approach, including the following:</li><li>A4.4: select power, attitude and configuration to safely control aeroplane (required standard 3)</li><li>A4.4: manoeuvre aeroplane clear of the ground and conduct after take-off procedures (required standard 3)</li><li>A4.4: make allowance for wind velocity during go-around (required standard 3)</li><li>A4.4: avoid wake turbulence (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Flapless Approach &amp; Landing and Missed Approach Flapless approach &amp; landing Missed landing procedure Missed approach procedure</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Propeller wash, rotor wash and jet blast and how they affect other aircraft [A1 4(i), A4 4(j)] Obtaining or calculating the crosswind and down or upwind components [A2 4(a)] Interpreting windsock indications to determine wind direction and speed [A2 4(c)] Causes of loss of control of aeroplane on landing [A4 4(f)] Judging descent profiles in various configurations [A6 4(d)] (partial flap &amp; flapless approaches) Prioritising activities during non-normal situations [A6 4(e)]</li><li>HF &amp; NTS Application of situational awareness to identify real or potential threats [NTS2 4(c)] Developing and implementing plans of action to remove and mitigate threats &amp; errors [NTS2 4(d)] Task management, organise workload [NTS2 4(i),(i)-(v)] Visual scan technique - use of clock code, identification of traffic Traffic management - speed control, circuit pattern adjustments</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-08',
    'RPL(A)8',
    'Circuits - Flapless & Missed Approach',
    'flight',
    60,
    'Introduce',
    ARRAY['Circuit consolidation', 'Flapless approach and landings', 'Missed approach procedure', 'Missed landing recovery Assess: maintain effective lookout']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>08_RPL(A) Circuits - Flapless and missed approaches.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    8,
    'Circuit Emergencies',
    'Recognition of take-off abnormalities, rejected take-off Simulated engine failure after take-off Simulated engine failure in the circuit Glide approach and landing Assess: operational communication using an aeronautical radio, operate radio equipment and transponder pre-flight actions and procedures, perform pre-flight inspection plan fuel requirements, manage fuel system start and stop engine, taxi aeroplane pre-take-off procedures, take-off, after take-off procedures climbing, descending, turning circuits and landings, including missed approach and missed landing recovery simulated engine failure on take-off and within the circuit area situational awareness, assess situations and make decisions, set priorities and manage tasks, recognise and manage threats, recognise and manage errors, recognise and manage undesired aircraft state',
    '<p><strong>Lesson overview</strong></p><ul><li>Recognition of take-off abnormalities, rejected take-off Simulated engine failure after take-off Simulated engine failure in the circuit Glide approach and landing Assess: operational communication using an aeronautical radio, operate radio equipment and transponder pre-flight actions and procedures, perform pre-flight inspection plan fuel requirements, manage fuel system start and stop engine, taxi aeroplane pre-take-off procedures, take-off, after take-off procedures climbing, descending, turning circuits and landings, including missed approach and missed landing recovery simulated engine failure on take-off and within the circuit area situational awareness, assess situations and make decisions, set priorities and manage tasks, recognise and manage threats, recognise and manage errors, recognise and manage undesired aircraft state</li></ul><ul><li>C1.2: Operational communication using an aeronautical radio</li><li>C1.2: maintain effective communication with others on operational matters (required standard 2)</li><li>C1.2: apply the phonetic alphabet (required standard 2)</li><li>C1.2: transmit numbers (required standard 2)</li><li>C1.2: make appropriate transmissions using standard aviation phraseology (required standard 2)</li><li>C1.2: use plain English effectively when standard phraseology is inadequate (required standard 2)</li><li>C1.2: receive appropriate responses to transmissions (required standard 2)</li><li>C1.2: respond to transmissions and take appropriate action (required standard 2)</li><li>C1.2: recognise and manage communication errors and misunderstandings effectively (required standard 2)</li><li>C1.2: seek clarification in the time available if a message is unclear or uncertainty exists (required standard 2)</li><li>C1.2: react appropriately to a variety of regional accents (required standard 2)</li><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: complete all required pre-flight administration documentation (required standard 2)</li><li>C2.1: obtain, interpret and apply information contained in the required pre-flight operational documentation, including the following:</li><li>C2.1: maintenance release (required standard 2)</li><li>C2.1: identify special aerodrome procedures (required standard 2)</li><li>C2.1: determine the suitability of the current weather conditions for the proposed flight (required standard 2)</li><li>C2.1: determine whether the aircraft is serviceable for the proposed flight (required standard 2)</li><li>C2.2: Perform pre-flight inspection</li><li>C2.2: identify and secure equipment and documentation that is required for the flight (required standard 2)</li><li>C2.2: complete an internal and external check of the aircraft (required standard 2)</li><li>C2.2: identify all defects or damage to the aircraft (required standard 2)</li><li>C2.2: ensure all aircraft locking and securing devices, covers and bungs are removed and stowed securely (required standard 2)</li><li>C4.1: Plan fuel requirements</li><li>C4.1: determine the required fuel reserves (required standard 2)</li><li>C4.1: determine the total fuel required for the flight (required standard 2)</li><li>C4.2: Manage fuel system</li><li>C4.2: verify fuel quantity on-board aircraft prior to flight using two independent methods (required standard 2)</li><li>C4.2: ensure the fuel caps are secured (required standard 2)</li><li>C4.2: perform fuel quality check prior to flight (required standard 2)</li><li>C4.2: ensure fuel drain cocks are closed (required standard 2)</li><li>C4.2: monitor fuel usage during the flight (required standard 2)</li><li>C4.2: perform fuel tank changes correctly (required standard 2)</li><li>C4.2: maintain fuel load within aircraft limits (required standard 2)</li><li>C4.2: operate fuel pumps and engine controls correctly (required standard 2)</li><li>A1.1: Start and stop engine</li><li>A1.1: perform engine start and after start actions (required standard 2)</li><li>A1.1: perform engine shutdown and after shutdown actions (required standard 2)</li><li>A1.1: manage engine start and shutdown malfunctions and emergencies (e.g. simulated engine fire on startup and shutdown) (required standard 3)</li><li>A1.1: considers ground surface in relation to contamination and propeller care during engine start and stop activities (required standard 2)</li><li>A1.2: Taxi aeroplane</li><li>A1.2: comply with taxiway and other aerodrome markings, right-of-way rules and ATC or marshalling instructions when applicable (required standard 2)</li><li>A1.2: perform applicable taxi checks, including the following:</li><li>A1.2: brakes and steering function normally and take appropriate action in the event of a malfunction (required standard 2)</li><li>A1.2: altimeter setting (required standard 2)</li><li>A1.2: maintain safe taxi speed and control of the aircraft (required standard 2)</li><li>A1.2: maintain safe spacing from other aircraft, obstructions, and persons (required standard 2)</li><li>A1.2: taxi the aeroplane along the centre of the taxiway (required standard 2)</li><li>A1.2: avoid causing a hazard to other aircraft, objects or persons (required standard 2)</li><li>A1.2: correct handling techniques are applied to take into account wind from all four quadrants (required standard 2)</li><li>A1.2: correctly manage the engine during taxi manoeuvres (required standard 2)</li><li>A2.1: Carry out pre take-off procedures</li><li>A2.1: correctly identify critical airspeeds, configurations, and emergency and abnormal procedures for normal and crosswind take-offs (required standard 2)</li><li>A2.1: work out a plan of action, in advance, to ensure the safest outcome in the event of abnormal operations (required standard 2)</li><li>A2.1: verify and correctly apply correction for the existing wind component to the take-off performance (required standard 2)</li><li>A2.1: perform all pre take-off and line-up checks required by the aircraft checklist (required standard 2)</li><li>A2.1: ensure approach path is clear of conflicting traffic and other hazards before lining up for take-off (required standard 2)</li><li>A2.1: align the aeroplane on the runway centreline (required standard 2)</li><li>A2.2: Take off aeroplane</li><li>A2.2: apply the controls correctly to maintain longitudinal alignment on the centreline of the runway, if appropriate, prior to initiating and during the take-off (required standard 2)</li><li>A2.2: adjust the power controls taking into account the existing conditions (required standard 2)</li><li>A2.2: monitor power controls, settings, and instruments during take-off to ensure all predetermined parameters are achieved and maintained (required standard 2)</li><li>A2.2: adjust the controls to attain the desired pitch attitude at the predetermined airspeed to attain the desired performance (required standard 2)</li><li>A2.2: perform the take-off applying the required pitch, roll and yaw inputs as appropriate in a smooth, coordinated manner (required standard 2)</li><li>A2.2: trim the aeroplane accurately (required standard 2)</li><li>A2.2: perform gear and flap retractions, power adjustments (as applicable) and other required pilot-related activities (required standard 2)</li><li>A2.2: maintain flight path along the runway extended centreline (required standard 2)</li><li>A2.2: apply the applicable noise abatement and wake turbulence avoidance procedures (required standard 2)</li><li>A2.2: recognise take-off abnormalities and take appropriate action to reject take-off (can be simulated) (required standard 2)</li><li>A2.4: Carry out after take-off procedures</li><li>A2.4: perform after take-off checklist (required standard 2)</li><li>A2.4: maintain the appropriate climb segment at the nominated heading and airspeed (required standard 2)</li><li>A2.4: manoeuvre according to local and standard procedures (required standard 2)</li><li>A2.4: maintain traffic separation (required standard 2)</li><li>A6.1: Manage engine failure - take-off (simulated)</li><li>A6.1: correctly identify an engine failure after take-off (required standard 2)</li><li>A6.1: apply the highest priority to taking action to control the aeroplane (required standard 2)</li><li>A6.1: maintain control of the aeroplane (required standard 2)</li><li>A6.1: perform recall actions (required standard 2)</li><li>A6.1: perform emergency actions as far as time permits (required standard 2)</li><li>A6.1: manoeuvre the aeroplane to achieve the safest possible outcome (required standard 2)</li><li>A6.1: advise others such as ATS and other aircraft of intentions if time permits (required standard 2)</li><li>A3.1: Climb aeroplane</li><li>A3.1: operate and monitor all aircraft systems when commencing, during, and completing a climbing flight manoeuvre (required standard 2)</li><li>A3.1: identify and avoid terrain and traffic (required standard 2)</li><li>A3.1: anticipate level-off altitude and achieve straight and level flight (required standard 2)</li><li>A3.3: Descend aeroplane</li><li>A3.3: operate and monitor all aircraft systems during descending flight manoeuvres (required standard 2)</li><li>A3.3: for the following descending manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.3: glide (required standard 2)</li><li>A3.3: approach configuration descent (flap and undercarriage) (required standard 2)</li><li>A3.4: Turn aeroplane</li><li>A3.4: operate and monitor all aircraft systems during turning flight manoeuvres (required standard 2)</li><li>A3.4: for the following turning manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.4: level turns (required standard 2)</li><li>A3.4: climbing turns (required standard 2)</li><li>A3.4: powered descending turns (required standard 2)</li><li>A3.4: gliding descending turns (required standard 2)</li><li>A3.4: complete turn manoeuvre on a nominated heading or geographical feature (required standard 2)</li><li>A3.4: turn aeroplane at varying rates to achieve specified tracks (required standard 2)</li><li>A3.4: manoeuvre aeroplane over specified tracks or geographical features (required standard 2)</li><li>A3.6: Perform circuits and approaches</li><li>A3.6: operate and monitor all aircraft systems when operating the aeroplane in the circuit (required standard 2)</li><li>A3.6: in accordance with specific local procedures, safely perform a full circuit pattern (5 legs) by balancing and trimming the aeroplane accurately while applying smooth, coordinated control inputs to achieve the required flight tolerances specified for the flight path flown during traffic pattern manoeuvres as follows:</li><li>A3.6: track upwind along extended centreline to 500 ft (required standard 2)</li><li>A3.6: establish and maintain crosswind leg tracking 90° to the runway (required standard 2)</li><li>A3.6: establish and maintain downwind leg tracking parallel to, and at a specified distance from, the runway at circuit height (required standard 2)</li><li>A3.6: establish base leg tracking 90° to the runway at a specified distance from the runway threshold (required standard 2)</li><li>A3.6: perform checks as required throughout circuit (required standard 2)</li><li>A3.6: establish the approach and landing configuration appropriate for the runway and meteorological conditions, and adjust the power plant controls as required for the following:</li><li>A3.6: commence and control approach descent path (required standard 2)</li><li>A3.6: adjust descent commencement point to take account of extended downwind leg or traffic adjustments (required standard 2)</li><li>A3.6: align and maintain aircraft on final approach flight path with specified or appropriate runway (required standard 2)</li><li>A3.6: set and maintain approach configuration not below 500 ft AGL (required standard 2)</li><li>A3.6: identify and maintain the nominated aiming point (required standard 2)</li><li>A3.6: maintain a stabilised approach angle at the nominated airspeed not less than 1.3Vs to the round-out height (required standard 2)</li><li>A3.6: verify existing wind conditions, make proper correction for drift, and maintain a precise ground track (required standard 2)</li><li>A3.6: apply speed allowances for wind gusts (required standard 2)</li><li>A3.6: configure aeroplane for landing (required standard 2)</li><li>A3.6: maintain aircraft separation and position in the circuit with reference to other aircraft traffic in the circuit area (required standard 2)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Circuit Emergencies Engine failure causes and prevention Engine failure during take-off Engine failure after take-off Engine failure in the circuit Vital actions and priorities Landing area selection Selection of aiming point Factors affecting glide performance Judgement and correction of overshoot/undershoot Glide approach and landing</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Judging descent profiles in various configurations [A6 4(d)], Aircraft performance in a glide [A6 4(i)] Prioritising activities during emergencies [A6 4(e)] Suitable fields for forced landings and precautionary landings [A6 4(g)]</li><li>HF &amp; NTS Effective communication under non-normal circumstances [NTS1 4(a)] Developing and implementing plans of action to remove and mitigate threats &amp; errors [NTS2 4(d)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Schedule pre-solo examination Schedule general English language proficiency assessment (if applicable - refer CASR 141.306)</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-09',
    'RPL(A)9',
    'Circuit Emergencies',
    'flight',
    60,
    'Introduce',
    ARRAY['Recognition of take-off abnormalities, rejected take-off', 'Simulated engine failure after take-off', 'Simulated engine failure in the circuit']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>09_RPL(A) Circuit Emergencies.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    9,
    'Circuits - Pre-solo assessment',
    'Consolidate circuits Assess: operational communication using an aeronautical radio, operate radio equipment and transponder pre-flight actions and procedures, perform pre-flight inspection plan fuel requirements, manage fuel system start and stop engine, taxi aeroplane pre-take-off procedures, take-off, after take-off procedures climbing, descending, turning circuits and landings, including missed approach and missed landing recovery simulated engine failure on take-off and within the circuit area situational awareness, assess situations and make decisions, set priorities and manage tasks, recognise and manage threats, recognise and manage errors, recognise and manage undesired aircraft state',
    '<p><strong>Lesson overview</strong></p><ul><li>Consolidate circuits Assess: operational communication using an aeronautical radio, operate radio equipment and transponder pre-flight actions and procedures, perform pre-flight inspection plan fuel requirements, manage fuel system start and stop engine, taxi aeroplane pre-take-off procedures, take-off, after take-off procedures climbing, descending, turning circuits and landings, including missed approach and missed landing recovery simulated engine failure on take-off and within the circuit area situational awareness, assess situations and make decisions, set priorities and manage tasks, recognise and manage threats, recognise and manage errors, recognise and manage undesired aircraft state</li></ul><ul><li>C1.2: Operational communication using an aeronautical radio</li><li>C2.1: Pre-flight actions and procedures</li><li>C2.2: Perform pre-flight inspection</li><li>C4.1: Plan fuel requirements</li><li>C4.2: Manage fuel system</li><li>A1.1: Start and stop engine</li><li>A1.2: Taxi aeroplane</li><li>A2.1: Carry out pre take-off procedures</li><li>A2.2: Take off aeroplane</li><li>A2.4: Carry out after take-off procedures</li><li>A6.1: Manage engine failure - take-off (simulated)</li><li>A3.1: Climb aeroplane</li><li>A3.3: Descend aeroplane</li><li>A3.4: Turn aeroplane</li><li>A3.6: Perform circuits and approaches</li><li>C3.1: Operate radio equipment</li><li>C3.3: Operate transponder</li><li>A6.2: Manage engine failure in the circuit area (simulated)</li><li>NTS1.2: Maintain situational awareness</li><li>NTS1.3: Assess situations and make decisions</li><li>NTS1.4: Set priorities and manage tasks</li><li>NTS2.1: Recognise and manage threats</li><li>NTS2.2: Recognise and manage errors</li><li>NTS2.3: Recognise and manage undesired aircraft state</li><li>A4.3: Conduct a missed approach</li><li>A4.4: Perform recovery from missed landing</li><li>A4.1: Land aeroplane</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing Revise circuit operations as required Guidelines for the conduct of the first solo flight</li><li>Underpinning knowledge Assess previously introduced underpinning knowledge Actions if communication from another aircraft misunderstood, or traffic within circuit not sighted</li><li>HF &amp; NTS Revise as required</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Theory examination Ensure pre-solo theory examination has been completed prior to commencing this training session</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-10',
    'RPL(A)10',
    'Circuits - Pre-solo assessment',
    'flight',
    48,
    'Assess',
    ARRAY['Consolidate circuits Assess: operational communication using an aeronautical radio, operate radio equipment and transpon']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>10_RPL(A) Circuits - pre-solo.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to first solo flight?# | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

