  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    11,
    'Circuit Consolidation',
    'Revise and consolidate circuits Confirm trainee competence to conduct subsequent solo circuits',
    '<p><strong>Lesson overview</strong></p><ul><li>Revise and consolidate circuits Confirm trainee competence to conduct subsequent solo circuits</li></ul><ul><li>C1.2: Operational communication using an aeronautical radio</li><li>C2.1: Pre-flight actions and procedures</li><li>C2.2: Perform pre-flight inspection</li><li>C4.1: Plan fuel requirements</li><li>C4.2: Manage fuel system</li><li>A1.1: Start and stop engine</li><li>A1.2: Taxi aeroplane</li><li>A2.1: Carry out pre take-off procedures</li><li>A2.2: Take off aeroplane</li><li>A2.4: Carry out after take-off procedures</li><li>A6.1: Manage engine failure - take-off (simulated)</li><li>A3.1: Climb aeroplane</li><li>A3.3: Descend aeroplane</li><li>A3.4: Turn aeroplane</li><li>A3.6: Perform circuits and approaches</li><li>C3.1: Operate radio equipment</li><li>C3.3: Operate Transponder</li><li>A6.2: Manage engine failure in the circuit area (simulated)</li><li>NTS1.2: Maintain situational awareness</li><li>NTS1.3: Assess situations and make decisions</li><li>NTS1.4: Set priorities and manage tasks</li><li>NTS2.1: Recognise and manage threats</li><li>NTS2.2: Recognise and manage errors</li><li>NTS2.3: Recognise and manage undesired aircraft state</li><li>A4.3: Conduct a missed approach</li><li>A4.4: Perform recovery from missed landing</li><li>A4.1: Land aeroplane</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing Revise circuit operations as required Guidelines for the conduct of further solo flight</li><li>Underpinning knowledge Revise and assess as required Actions if communication from another aircraft misunderstood, or traffic within circuit not sighted Missed approach procedure Missed landing procedure Circuit emergencies</li><li>HF &amp; NTS Revise as required</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
