  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    15,
    'Advanced Stalling',
    'Recognition and recovery from nose high unusual attitude flight conditions Revise incipient stall and stall from straight and level Advanced stalls - stall entry from climbing, descending (including glide configuration), turning Incipient spins - entry from straight and level, climbing and turning Circuit departure and arrival procedures Local area airspace procedures Weather forecasts Assess: advanced stalling and incipient spin recovery',
    '<p><strong>Lesson overview</strong></p><ul><li>Recognition and recovery from nose high unusual attitude flight conditions Revise incipient stall and stall from straight and level Advanced stalls - stall entry from climbing, descending (including glide configuration), turning Incipient spins - entry from straight and level, climbing and turning Circuit departure and arrival procedures Local area airspace procedures Weather forecasts Assess: advanced stalling and incipient spin recovery</li></ul><ul><li>C1.2: Communicating face-to-face</li><li>C1.2: communicate effectively in unfamiliar, stressful or non-standard situations (required standard 3)</li><li>C1.2: communicate effectively in unexpected, stressful or non-standard situations using standard phraseology or plain English (required standard 3)</li><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: obtain, interpret and apply information contained in the required pre-flight operational documentation, including the following:</li><li>C2.1: weather forecasts (required standard 3)</li><li>C2.1: identify all relevant radio and navigation aid facilities to be used during the flight (if applicable) (required standard 3)</li><li>C2.1: determine the suitability of the forecast weather conditions for the proposed flight (required standard 3)</li><li>A3.7: Local area airspace</li><li>A3.7: using an appropriate chart, for the local area and circuit area:</li><li>A3.7: identify geographical features (required standard 3)</li><li>A3.7: identify geographical limits (required standard 3)</li><li>A3.7: identify restricted, controlled and uncontrolled airspace areas (required standard 3)</li><li>A3.7: state local airspace limits (required standard 3)</li><li>A3.7: identify the transit route between the departure aerodrome and training area (required standard 3)</li><li>A3.7: identify the geographical limits of the training area (required standard 3)</li><li>A3.7: identify aerodromes and landing areas within the local area (required standard 3)</li><li>A3.7: maintain orientation and pinpoint location by using geographical features and a local area chart (required standard 3)</li><li>A3.7: transit from the circuit area and transit to the designated training area (required standard 3)</li><li>A3.7: operate safely within a transit lane (if applicable) (required standard 3)</li><li>A3.7: remain clear of restricted, controlled and other appropriately designated airspace (required standard 3)</li><li>A3.7: operate safely in the vicinity of local aerodromes and landing areas (required standard 3)</li><li>A3.7: transit from the designated training area to the circuit area (required standard 3)</li><li>A3.7: set QNH appropriately (required standard 3)</li><li>A3.7: correctly determine which runway is to be used for landing (required standard 3)</li><li>A3.7: ensure runway is serviceable and available (required standard 3)</li><li>A3.7: position aircraft for arrival into the circuit (required standard 3)</li><li>A5.1: Enter and recover from stall</li><li>A5.1: perform pre-manoeuvre checks for stalling (required standard 2)</li><li>A5.1: recognise stall signs and symptoms (required standard 2)</li><li>A5.1: control the aeroplane by applying the required pitch, roll and yaw inputs as appropriate in a smooth, coordinated manner, trim aeroplane accurately to enter and recover from the following manoeuvres:</li><li>A5.1: incipient stall (required standard 2)</li><li>A5.1: stall with full power applied (required standard 2)</li><li>A5.1: stall under the following conditions:</li><li>A5.1: (A) straight and level flight (required standard 2)</li><li>A5.1: (B) climbing (required standard 2)</li><li>A5.1: (C) descending (required standard 2)</li><li>A5.1: (E) turning (required standard 2)</li><li>A5.1: perform stall recovery as follows:</li><li>A5.1: positively reduce angle of attack (required standard 2)</li><li>A5.1: use power available and excess height to increase the aircraft energy state (required standard 2)</li><li>A5.1: minimise height loss for simulated low altitude condition (required standard 2)</li><li>A5.1: re-establish desired flight path and aircraft control (required standard 2)</li><li>A5.1: recover from stall in simulated partial and complete engine failure configurations (required standard 2)</li><li>A5.2: Recover from incipient spin</li><li>A5.2: perform pre-manoeuvre checks for an incipient spin (required standard 2)</li><li>A5.2: recognise an incipient spin (required standard 2)</li><li>A5.2: use the aeroplane&#x27;s attitude and power controls to execute an incipient spin manoeuvre from the following flight conditions and, using correct recovery technique, regain straight and level flight with height loss commensurate with the available altitude (simulated ground base height may be set):</li><li>A5.2: straight and level flight (required standard 2)</li><li>A5.2: climbing (required standard 2)</li><li>A5.2: turning (required standard 2)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Advanced Stalling Review essential knowledge from stalling brief Advanced stalling - stall recognition, recovery and control technique, entry from the following manoeuvres: climbing descending (approach configuration and glide, simulated partial and complete engine failure configurations) turning climbing turn descending turn (approach configuration and glide) Recognition of and recovery from an incipient spin, entry from the following manoeuvres: straight and level climbing turning Application in flight and checklist procedures (e.g. HASELL)</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Local weather patterns [C2 4(e)] Documented radio procedures relevant to the VFR [C3 4(b)] (relevant to transit to and from, and operations within, the training area) The environmental conditions that represent VMC [A1 4(h) &amp; A3 4(n)]], Day VFR flight rules [A1 4(j) &amp; A3 4(o)] Relationship between AOB, LF &amp; stall speed [A3 4(i)] Relationship between induced drag and operating at low speed [A3 4(j)] Local area operating procedures [A3 4(p)] (relevant to transit to and from, and operations within, the training area), training area lateral &amp; vertical boundaries Aerodynamic and aeroplane operational considerations related to slow flight, stalling, spinning &amp; upset aeroplane states [A5 4(b)(i)-(xii)]</li><li>HF &amp; NTS Task management [NTS1 4(b)] Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)] Use of checklists and standard operating procedures to prevent errors [NTS2 4(h)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-16',
    'RPL(A)16',
    'Advanced Stalling',
    'flight',
    60,
    'Practice',
    ARRAY['Recognition and recovery from nose high unusual attitude flight conditions', 'Revise incipient stall and stall from straight and level', 'Advanced stalls - stall entry from climbing, descending (including glide configuration), turning', 'Incipient spins - entry from straight and level, climbing and turning', 'Circuit departure and arrival procedures', 'Local area airspace procedures', 'Weather forecasts Assess: advanced stalling and incipient spin recovery']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>16_RPL(A) Advanced Stalling.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    16,
    'Forced Landings',
    'Weight and balance, take-off and landing performance calculations, fuel calculations Refuelling Practice forced landings (simulated complete and partial engine failure conditions) Manage other simulated abnormal situations Passenger management (simulated) Assess: engine start and shutdown malfunctions and emergencies climbing (cruise and best rate) descending (cruise descent)',
    '<p><strong>Lesson overview</strong></p><ul><li>Weight and balance, take-off and landing performance calculations, fuel calculations Refuelling Practice forced landings (simulated complete and partial engine failure conditions) Manage other simulated abnormal situations Passenger management (simulated) Assess: engine start and shutdown malfunctions and emergencies climbing (cruise and best rate) descending (cruise descent)</li></ul><ul><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: using the aircraft documents, calculate the following for a given set of environmental and operational conditions:</li><li>C2.1: weight and balance (required standard 3)</li><li>C2.1: take-off and landing performance (required standard 3)</li><li>C2.1: fuel requirements (required standard 3)</li><li>C4.1: Plan fuel requirements</li><li>C4.1: determine the quantity of fuel required taking into account operational requirements and relevant abnormal or emergency conditions and contingencies (required standard 3)</li><li>C4.3: Refuel aircraft</li><li>A1.1: Start and stop engine</li><li>A1.1: manage engine start and shutdown malfunctions and emergencies (e.g. flooded start, engine fire on start up, engine fire on shutdown) (required standard 2)</li><li>A1.2: Taxi aeroplane</li><li>A1.2: use aerodrome or landing area charts to taxi aircraft (required standard 3)</li><li>A1.2: perform applicable taxi checks, including the following:</li><li>A1.2: instruments for correct readings (required standard 3)</li><li>A3.1: Climb aeroplane</li><li>A3.1: for the following climbing manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.1: cruise climb (required standard 2)</li><li>A3.1: best rate climb (required standard 2)</li><li>A3.3: Descend aeroplane</li><li>A3.3: for the following descending manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.3: powered (required standard 2)</li><li>A3.3: anticipate level-off altitude and achieve straight and level flight (required standard 2)</li><li>C3.3: Operate transponder</li><li>C3.3: operate a transponder during abnormal and emergency operations (required standard 2)</li><li>C3.3: recall transponder emergency codes (required standard 2)</li><li>A6.3: Perform forced landing (simulated)</li><li>A6.3: after a simulated complete engine failure has occurred, without prior indications, carry out the following:</li><li>A6.3: identify complete power failure condition and control aeroplane (required standard 3)</li><li>A6.3: perform immediate actions (required standard 3)</li><li>A6.3: formulate and describe a recovery plan, including selecting the most suitable landing area (required standard 3)</li><li>A6.3: establish optimal gliding flight path to position the aeroplane for a landing on the selected landing area (required standard 3)</li><li>A6.3: perform emergency procedures and land the aeroplane if the engine cannot be restarted as time permits (required standard 3)</li><li>A6.3: advise ATS or other agencies capable of providing assistance of situation and intentions (required standard 3)</li><li>A6.3: re-brief passengers about flight situation, brace position and harness security (required standard 3)</li><li>A6.3: land the aeroplane ensuring safest outcome if an engine restart is not achieved (required standard 3)</li><li>A6.3: after a simulated partial engine failure has occurred, without prior indications, carry out the following:</li><li>A6.3: identify partial power failure condition (required standard 3)</li><li>A6.3: perform recall actions (required standard 3)</li><li>A6.3: adjust flight controls to re-establish flight path that maximises performance for partial power condition and maintain a safe airspeed margin above stall speed (required standard 3)</li><li>A6.3: establish radio communications where possible (required standard 3)</li><li>A6.3: perform partial engine failure actions (required standard 3)</li><li>A6.3: formulate a plan to recover aeroplane to a safe landing area or aerodrome, taking into account that partial failure might lead to a full power failure at any time (required standard 3)</li><li>A6.3: manoeuvre the aeroplane to a selected landing area or aerodrome using the remaining power to establish an optimal aircraft position for a safe landing (required standard 3)</li><li>A6.3: advise ATS or other agencies capable of providing assistance of situation and intentions (required standard 3)</li><li>A6.3: re-brief passengers about flight situation, brace position and harness security (required standard 3)</li><li>A6.3: maintain a contingency plan for coping with a full power failure throughout the manoeuvre (required standard 3)</li><li>A6.3: when a safe landing position is established, shut down and secure engine and aeroplane (required standard 3)</li><li>A6.5: Manage other abnormal situations (simulated) (e.g. simulated engine fire in flight)</li><li>A6.5: correctly identify the situation and maintain safe control of the aeroplane at all times (required standard 3)</li><li>A6.5: manage abnormal and emergency situations in accordance with relevant emergency procedures and regulatory requirements (required standard 3)</li><li>A6.5: follow appropriate emergency procedures while maintaining control of the aeroplane (required standard 3)</li><li>A6.5: correctly identify when an emergency evacuation of an aeroplane is required (required standard 3)</li><li>A6.5: execute a simulated emergency evacuation of an aeroplane (required standard 3)</li><li>A6.5: advise ATS or other agencies capable of providing assistance of situation and intentions (required standard 3)</li><li>C4.2: Manage fuel system</li><li>C4.2: operate the fuel cross-feed system correctly (if fitted) (required standard 3)</li><li>C5.1: Manage passengers</li><li>C5.1: supervise passenger safety (required standard 3)</li><li>C5.1: encourage passengers to participate in and contribute to the safe outcome of the flight (required standard 3)</li><li>C5.1: conduct pre-flight passenger safety briefing (required standard 3)</li><li>C5.1: ensure passengers are aware of, and avoid interference with, flight and systems controls (required standard 3)</li><li>C5.1: ensure passengers are aware of, and comply with, the use of seat harnesses (required standard 3)</li><li>C5.1: ensure passengers are aware of the use of escape hatches, exits and emergency equipment on board the aircraft (required standard 3)</li><li>C5.1: manage passenger safety in the event of abnormal or in-flight emergency situations (required standard 3)</li><li>C5.2: Aid and assist passengers</li><li>C5.2: establish and maintain clear communications with passengers (required standard 3)</li><li>C5.2: assist with passenger comfort both when airside and in flight (required standard 3)</li><li>NTS1.4: Set priorities and manage tasks</li><li>NTS1.4: use technology to reduce workload and improve cognitive and manipulative activities (required standard 3)</li><li>NTS1.5: Maintain effective communications and interpersonal relationships</li><li>NTS1.5: establish and maintain effective and efficient communications and interpersonal relationships with all stakeholders to ensure the optimum outcome of the flight (required standard 3)</li><li>NTS1.5: define and explain objectives to stakeholders (required standard 3)</li><li>NTS1.5: demonstrate a level of assertiveness that ensures the optimum completion of the flight (required standard 3)</li><li>NTS2.2: Recognise and manage errors</li><li>NTS2.2: monitor the following to collect and analyse information to identify potential or actual errors:</li><li>NTS2.2: aircraft systems using a systematic scan technique (required standard 3)</li><li>NTS2.2: the flight environment (required standard 3)</li><li>NTS2.2: other crew (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Practice Forced Landings Common engine failure causes (partial and complete engine failures) Immediate/vital actions (including initial trouble checks) Wind indicators and assessment Landing area selection Planning and flying the approach, actions if high or low Detailed trouble checks Radio procedures (MAYDAY call) Passenger briefing and management Final approach judgement, recognition and management of over/undershoot Shutdown checks Engine management considerations during simulated engine failures</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Variations to planned fuel consumption [C4 4(h)] Managing passengers during abnormal or emergency situations [C5 4(a)] Local procedures for movement of passengers [C5 4(b)], Security requirements [C5 4(c)] Dangerous goods awareness [C5 4(d)], Health and safety regulations and best practice [C5 4(e)] Take-off distance required calculation [A2 4(d)], Aerodrome charts [A2 4(e)] Local topographical charts- identify safe areas for engine-failure purposes, noise-abatement considerations [A2 4(f)] Aircraft weight &amp; balance and how to calculate centre of gravity [A1 4(f), A3 4(f) &amp; A4 4(d)] Engine failure scenarios and procedures for partial and complete power loss [A6 4(a)] Forced landing scenarios and procedures [A6 4(b)], Judging descent profiles in various configurations [A6 4(d)] Prioritising activities during emergencies and non-normal situations [A6 4(e)] Ditching [A6 4(f)] Suitable fields for forced landings [A6 4(g)] Considerations when practising emergencies and non-normal operations [A6 4(h)] Aircraft performance in a glide (straight &amp; turning) [A6 4(i)] Effects of partial engine power on performance, flight profile, range and landing options [A6 4(k)] Passenger control and briefing [A6 4(m)] Low-flying hazards[A6 4(o)]</li><li>HF &amp; NTS Effective communication under normal and non-normal circumstances [NTS1 4(a), NTS2 4(a)] Threat and error management detailing processes that can be used to identify and mitigate or control threats and errors [NTS2 4(b)] Task management [NTS2 4(I)], including: workload organisation and priority setting to ensure optimum safe outcome of the flight event planning to occur in a logical and sequential manner anticipating events to ensure sufficient opportunity is available for completion using technology to reduce workload and improve cognitive and manipulative activities task prioritisation and protection whilst filtering and managing real time information Aviate, Navigate, Communicate Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)] Use of checklists and standard operating procedures to prevent errors [NTS2 4(h)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-17',
    'RPL(A)17',
    'Forced Landings',
    'flight',
    60,
    'Practice',
    ARRAY['Weight and balance, take-off and landing performance calculations, fuel calculations', 'Refuelling', 'Practice forced landings (simulated complete and partial engine failure conditions)', 'Manage other simulated abnormal situations']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>17_RPL(A) Forced Landings.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    17,
    'Steep Turns',
    'Revise weight and balance, take-off and landing performance calculations, fuel calculations 45° angle of bank level turns Maximum rate turns - 60° angle of bank Minimum radius turns - 60° angle of bank Steep gliding turn Spiral dive recognition and recovery Sideslipping (where flight manual permits) Flapless approach and landing Assess: engine start and shutdown malfunctions and emergencies climbing (cruise and best rate) descending (cruise descent) local area airspace forced landing (simulated complete engine failure) radio failure procedure (inbound from training area)',
    '<p><strong>Lesson overview</strong></p><ul><li>Revise weight and balance, take-off and landing performance calculations, fuel calculations 45° angle of bank level turns Maximum rate turns - 60° angle of bank Minimum radius turns - 60° angle of bank Steep gliding turn Spiral dive recognition and recovery Sideslipping (where flight manual permits) Flapless approach and landing Assess: engine start and shutdown malfunctions and emergencies climbing (cruise and best rate) descending (cruise descent) local area airspace forced landing (simulated complete engine failure) radio failure procedure (inbound from training area)</li></ul><ul><li>C2.1: Pre-flight actions and procedures (weight &amp; balance, t/o &amp; ldg performance, fuel requirements)</li><li>A1.1: Start and stop engine (start and stop malfunctions and emergencies)</li><li>A3.1: Climb aeroplane (cruise and best rate)</li><li>A3.3: Descend aeroplane (powered)</li><li>A3.7: Local area airspace</li><li>A3.7: using an appropriate chart, for the local area and circuit area:</li><li>A3.7: identify geographical features (required standard 2)</li><li>A3.7: identify geographical limits (required standard 2)</li><li>A3.7: identify restricted, controlled and uncontrolled airspace areas (required standard 2)</li><li>A3.7: state local airspace limits (required standard 2)</li><li>A3.7: identify the transit route between the departure aerodrome and training area (required standard 2)</li><li>A3.7: identify the geographical limits of the training area (required standard 2)</li><li>A3.7: identify aerodromes and landing areas within the local area (required standard 2)</li><li>A3.7: maintain orientation and pinpoint location by using geographical features and a local area chart (required standard 2)</li><li>A3.7: transit from the circuit area and transit to the designated training area (required standard 2)</li><li>A3.7: operate safely within a transit lane (if applicable) (required standard 2)</li><li>A3.7: remain clear of restricted, controlled and other appropriately designated airspace (required standard 2)</li><li>A3.7: operate safely in the vicinity of local aerodromes and landing areas (required standard 2)</li><li>A3.7: transit from the designated training area to the circuit area (required standard 2)</li><li>A3.7: set QNH appropriately (required standard 2)</li><li>A3.7: correctly determine which runway is to be used for landing (required standard 2)</li><li>A3.7: ensure runway is serviceable and available (required standard 2)</li><li>A3.7: position aircraft for arrival into the circuit (required standard 2)</li><li>A5.3: Turn aeroplane steeply</li><li>A5.3: pre-manoeuvre checks for steep turning (required standard 3)</li><li>A5.3: steep level turn using a nominated bank angle, ending on a nominated heading or geographical feature, without altitude change (required standard 3)</li><li>A5.3: steep descending turn using a nominated bank angle, ending on a nominated heading or geographical feature ending on a nominated altitude (required standard 3)</li><li>A5.3: aeroplane operating limits are not exceeded (required standard 3)</li><li>A6.6: Recover from unusual flight attitudes (spiral dive recognition and recovery)</li><li>A6.6: identify nose-low unusual attitude flight condition (required standard 3)</li><li>A6.6: recover from nose-low unusual attitudes by adjusting pitch, bank and power to resume controlled and balanced flight (required standard 3)</li><li>A6.6: apply controlled corrective action while maintaining aircraft performance within limits (required standard 3)</li><li>A5.4: Sideslip aeroplane (where flight manual permits)</li><li>A5.4: straight sideslip:</li><li>A5.4: induce slip to achieve increased rate of descent while maintaining track and airspeed (required standard 3)</li><li>A5.4: adjust rate of descent by coordinating angle of bank and applied rudder (required standard 3)</li><li>A5.4: sideslipping turn by adjusting the bank angle to turn through minimum heading change of 90° at constant airspeed using sideslip, and exiting the turn on a specified heading or geographical feature, within tolerance (required standard 3)</li><li>A5.4: recover from a sideslip and return the aeroplane to balanced flight (required standard 3)</li><li>A6.3: Perform forced landing (simulated)</li><li>A6.3: after a simulated complete engine failure has occurred, without prior indications, carry out the following:</li><li>A6.3: identify complete power failure condition and control aeroplane (required standard 2)</li><li>A6.3: perform immediate actions (required standard 2)</li><li>A6.3: formulate and describe a recovery plan, including selecting the most suitable landing area (required standard 2)</li><li>A6.3: establish optimal gliding flight path to position the aeroplane for a landing on the selected landing area (required standard 2)</li><li>A6.3: perform emergency procedures and land the aeroplane if the engine cannot be restarted as time permits (required standard 2)</li><li>A6.3: advise ATS or other agencies capable of providing assistance of situation and intentions (required standard 2)</li><li>A6.3: re-brief passengers about flight situation, brace position and harness security (required standard 2)</li><li>A6.3: land the aeroplane ensuring safest outcome if an engine restart is not achieved (required standard 2)</li><li>C3.2: Manage R/T equipment malfunctions</li><li>C3.2: perform radio failure procedures (required standard 2)</li><li>C3.2: use fault finding procedures and perform corrective actions (required standard 2)</li><li>A4.1: Land aeroplane (revise flapless approach and landing)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Steep Turns Review essential knowledge from turning brief Aerodynamic forces during a turn Bank angle and load factor Load factor and effect on stalling speed Maximum rate turns (including collision avoidance) Minimum radius turns Spiral dive - causes, symptoms and recovery technique Sideslipping, application, precautions, flight manual limitations Attitude flying Instrument indications Application in flight</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Radio failure procedures and light signals, including interpretation and actions required [C3 4(f)] Hazards when performing performance manoeuvres [A3 4(g)] Operational circumstances where steep turns are required [A5 4(a)] Aerodynamic and aeroplane operational considerations related to sideslipping, steep turns and upset aeroplane states [A5 4(b)], including but not limited to: relationship between angle of attack and stall effects of weight, ‘g’ force and angle of attack dangers of unbalanced flight symmetrical and rolling ‘g’ force limitations higher stall speeds when aeroplane is turning effects on fuel, pitot and flap systems Contents of the flight manual and pilot owner handbook [A5 4(c)] Hazards of unbalanced flight [A5 4(g)], hazard of sideslip at low altitude [A6 4(j)]</li><li>HF &amp; NTS Effective communication under normal and non-normal circumstances [NTS1 4(a), NTS2 4(a)] Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)] Use of checklists and standard operating procedures to prevent errors [NTS2 4(h)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-18',
    'RPL(A)18',
    'Steep Turns',
    'flight',
    60,
    'Practice',
    ARRAY['Maximum rate turns - 60° angle of bank', 'Minimum radius turns - 60° angle of bank', 'Steep gliding turn', 'Spiral dive recognition and recovery', 'Sideslipping (where flight manual permits)']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>18_RPL(A) Steep Turns.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    18,
    'Crosswind Circuits',
    'Crosswind circuits Review missed approach and recovery from missed landing Review engine failure after take-off and in the circuit area Assess: local observations, use of weather forecasts refuelling crosswind take-off and landing operational communication NTS lookout, effective communications and interpersonal relationships',
    '<p><strong>Lesson overview</strong></p><ul><li>Crosswind circuits Review missed approach and recovery from missed landing Review engine failure after take-off and in the circuit area Assess: local observations, use of weather forecasts refuelling crosswind take-off and landing operational communication NTS lookout, effective communications and interpersonal relationships</li></ul><ul><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: obtain, interpret and apply information contained in the required pre-flight operational documentation, including the following:</li><li>C2.1: weather forecasts (required standard 2)</li><li>C2.1: local observations (required standard 2)</li><li>C4.3: Refuel aircraft</li><li>A2.3: Take off aeroplane in a crosswind</li><li>A2.3: perform a take-off in an aeroplane making appropriate adjustments for the crosswind conditions (required standard 2)</li><li>A2.3: maintain the runway centreline and extended centreline (required standard 2)</li><li>A6.1: Manage engine failure - take-off (simulated)</li><li>A6.1: ensure passengers adopt brace position (required standard 3)</li><li>A3.6: Perform circuits and approaches</li><li>A6.2: Manage engine failure in the circuit area (simulated)</li><li>A6.2: re-brief passengers about flight situation, brace position and harness security (required standard 3)</li><li>C1.2: Operational communication using an aeronautical radio</li><li>C1.2: communicate effectively in unfamiliar, stressful or non-standard situations (required standard 2)</li><li>C1.2: communicate effectively in unexpected, stressful or non-standard situations using standard phraseology or plain English (required standard 2)</li><li>NTS1.1: Maintain effective lookout</li><li>NTS1.1: maintain traffic separation using a systematic visual scan technique at a rate determined by traffic density, visibility and terrain (required standard 1)</li><li>NTS1.1: maintain radio listening watch and interpret transmissions to determine traffic location and intentions (required standard 1)</li><li>NTS1.1: perform airspace-cleared procedure before commencing any manoeuvre (required standard 1)</li><li>NTS1.5: Maintain effective communications and interpersonal relationships</li><li>NTS1.5: establish and maintain effective and efficient communications and interpersonal relationships with all stakeholders to ensure the optimum outcome of the flight (required standard 2)</li><li>NTS1.5: define and explain objectives to stakeholders (required standard 2)</li><li>NTS1.5: demonstrate a level of assertiveness that ensures the optimum completion of the flight (required standard 2)</li><li>A4.2: Land aeroplane in a crosswind</li><li>A4.2: verify existing wind conditions, make proper correction for drift, and maintain a precise ground track (required standard 2)</li><li>A4.2: configure the aeroplane for the crosswind conditions (required standard 2)</li><li>A4.2: control the aeroplane during the transition from final approach to touchdown and during after-landing roll to compensate for the crosswind conditions (required standard 2)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Crosswind Circuits Check essential knowledge from circuits briefing Aeroplane crosswind limitations/maximum demonstrated crosswind Company crosswind limitations, personal limitation Drift compensation considerations Calculation of crosswind component for landing Crosswind take-off, approach and landing technique</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Obtaining or calculating the crosswind and down or upwind components [A2 4(a)] Interpreting windsock indications and determining wind direction and speed [A2 4(c)] Dangers associated with mechanical and wake turbulence [A3 4(k)] Aeroplane limitations [A4 4(c)] Options when local conditions are not suitable for landing [A4 4(e)] Causes of loss of control of aeroplane on landing [A4 4(f)] Contents of the aircraft flight manual and pilot’s operating handbook [A4 4(g)]</li><li>HF &amp; NTS Effective communication under normal and non-normal circumstances [NTS1 4(a), NTS2 4(a)] Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-19',
    'RPL(A)19',
    'Crosswind Circuits',
    'flight',
    60,
    'Practice',
    ARRAY['Crosswind circuits', 'Review missed approach and recovery from missed landing']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>19_RPL(A) Crosswind Circuits.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
