    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    19,
    'Pre-training area solo assessment',
    'Revise and assess: forced landing steep turns sideslipping (where flight manual permits) advanced stalling, incipient spins recovery from unusual flight attitudes operational communication, radio failure procedure (inbound from training area) NTS lookout, effective communications and interpersonal relationships crosswind take-off and landing local area airspace',
    '<p><strong>Lesson overview</strong></p><ul><li>Revise and assess: forced landing steep turns sideslipping (where flight manual permits) advanced stalling, incipient spins recovery from unusual flight attitudes operational communication, radio failure procedure (inbound from training area) NTS lookout, effective communications and interpersonal relationships crosswind take-off and landing local area airspace</li></ul><ul><li>C2.1: Pre-flight actions and procedures (weather forecast, location observations)</li><li>A2.3: Take off aeroplane in a crosswind</li><li>C1.2: Operational communication using an aeronautical radio</li><li>A5.1: Enter and recover from stall (stall with full power, climbing, descending, turning, simulated partial and complete engine failure configurations)</li><li>A5.2: Recover from incipient spin (from straight &amp; level flight, climbing, turning)</li><li>A5.3: Turn aeroplane steeply</li><li>A5.3: pre-manoeuvre checks for steep turning (required standard 2)</li><li>A5.3: steep level turn using a nominated bank angle, ending on a nominated heading or geographical feature, without altitude change (required standard 2)</li><li>A5.3: steep descending turn using a nominated bank angle, ending on a nominated heading or geographical feature ending on a nominated altitude (required standard 2)</li><li>A5.3: aeroplane operating limits are not exceeded (required standard 2)</li><li>A6.6: Recover from unusual flight attitudes</li><li>A6.6: identify nose-high or nose-low unusual attitude flight condition (required standard 2)</li><li>A6.6: recover from nose-low or nose-high unusual attitudes by adjusting pitch, bank and power to resume controlled and balanced flight (required standard 2)</li><li>A6.6: apply controlled corrective action while maintaining aircraft performance within limits (required standard 2)</li><li>A6.3: Perform forced landing (simulated) (complete engine failure)</li><li>A5.4: Sideslip aeroplane (where flight manual permits)</li><li>A5.4: straight sideslip:</li><li>A5.4: induce slip to achieve increased rate of descent while maintaining track and airspeed (required standard 2)</li><li>A5.4: adjust rate of descent by coordinating angle of bank and applied rudder (required standard 2)</li><li>A5.4: sideslipping turn by adjusting the bank angle to turn through minimum heading change of 90° at constant airspeed using sideslip, and exiting the turn on a specified heading or geographical feature, within tolerance (required standard 2)</li><li>A5.4: recover from a sideslip and return the aeroplane to balanced flight (required standard 2)</li><li>A3.7: Local area airspace</li><li>NTS1.1: Maintain effective lookout</li><li>NTS1.5: Maintain effective communications and interpersonal relationships</li><li>C3.2: Manage R/T equipment malfunctions</li><li>A4.2: Land aeroplane in a crosswind</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing Sequences to be reviewed and assessed Emphasise restrictions and limitations when practising sequences solo Local area operating procedures and weather considerations Others as required</li><li>Underpinning knowledge Assess previously introduced underpinning knowledge</li><li>HF &amp; NTS Effective communication under normal and non-normal circumstances [NTS1 4(a), NTS2 4(a)] Threat and error management detailing processes that can be used to identify and mitigate or control threats and errors [NTS2 4(b)] Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Theory examination Ensure pre-training area solo theory examination has been completed prior to commencing this training session</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-20',
    'RPL(A)20',
    'Pre-training area solo assessment',
    'flight',
    60,
    'Assess',
    ARRAY['Revise and assess: forced landing steep turns sideslipping (where flight manual permits) advanced stalling, incipient sp']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>20_RPL(A) Pre training area solo.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to first training area solo flight?# | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
