    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    20,
    'First training area solo',
    'Perform practice forced landings solo, in accordance with the limitations and guidelines advised by the authorising flight instructor Suggested flight time: 1.0 hour',
    '<p><strong>Lesson overview</strong></p><ul><li>Perform practice forced landings solo, in accordance with the limitations and guidelines advised by the authorising flight instructor Suggested flight time: 1.0 hour</li></ul><ul><li>Perform practice forced landings solo, in accordance with the limitations and guidelines advised by the authorising flight instructor Suggested flight time: 1.0 hour</li><li>Operational Limitations: During solo flight, trainees must only be authorised to practise sequences that have been assessed to performance standard 2 or 1, on a minimum of two separate flights. Except in emergency or urgency situations, or in the interests of maintaining safety, the trainee must not operate contrary to the limitations and guidelines specified by the authorising flight instructor.</li></ul>',
    '<ul><li>Operational Limitations: During solo flight, trainees must only be authorised to practise sequences that have been assessed to performance standard 2 or 1, on a minimum of two separate flights. Except in emergency or urgency situations, or in the interests of maintaining safety, the trainee must not operate contrary to the limitations and guidelines specified by the authorising flight instructor.</li></ul>',
    'casa-rpl-a-21',
    'RPL(A)21',
    'First training area solo',
    'flight',
    60,
    'Practice',
    ARRAY['Suggested flight time: 1.0 hour']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>21_RPL(A) First Training Area Solo.DOCX</li></ul><ul><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    21,
    'Circuits - Short Field t/o & Landing',
    'Pre-flight actions and procedures - MEL, NOTAMs, GNSS (if applicable), ERSA, AIP Circuits - ‘short field’ take-off and landing Revise circuit emergencies Assess: weight and balance, take-off and landing performance charts, fuel requirement calculations best angle climb',
    '<p><strong>Lesson overview</strong></p><ul><li>Pre-flight actions and procedures - MEL, NOTAMs, GNSS (if applicable), ERSA, AIP Circuits - ‘short field’ take-off and landing Revise circuit emergencies Assess: weight and balance, take-off and landing performance charts, fuel requirement calculations best angle climb</li></ul><ul><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: obtain, interpret and apply information contained in the required pre-flight operational documentation, including the following:</li><li>C2.1: minimum equipment list (MEL) (required standard 3)</li><li>C2.1: Notice to Airmen (NOTAM) (required standard 3)</li><li>C2.1: global navigation satellite system (GNSS) receiver autonomous integrity monitoring (RAIM) information (required standard 3)</li><li>C2.1: En Route Supplement Australia (ERSA) (required standard 3)</li><li>C2.1: Aeronautical Information Package (AIP) (required standard 3)</li><li>C2.1: using the aircraft documents, calculate the following for a given set of environmental and operational conditions:</li><li>C2.1: weight and balance (required standard 2)</li><li>C2.1: take-off and landing performance (required standard 2)</li><li>C2.1: fuel requirements (required standard 2)</li><li>A2.5: Take off aeroplane from ‘short field’</li><li>A2.5: calculate take-off and landing performance in accordance with the aeroplane&#x27;s performance charts (required standard 3)</li><li>A2.5: perform take-off aeroplane to achieve the minimum length take-off performance (required standard 3)</li><li>A2.5: perform take-off aeroplane to achieve the obstacle clearance parameters (required standard 3)</li><li>A3.1: Climb aeroplane</li><li>A3.1: for the following climbing manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.1: best angle climb (required standard 2)</li><li>A6.1: Manage engine failure - take-off (simulated)</li><li>A6.2: Manage engine failure in the circuit area (simulated)</li><li>A4.5: Short landing</li><li>A4.5: land aeroplane at nominated touchdown point at minimum speed (required standard 3)</li><li>A4.5: control ballooning during flare (required standard 3)</li><li>A4.5: control bouncing after touchdown (required standard 3)</li><li>A4.5: maintain direction after touchdown (required standard 3)</li><li>A4.5: apply maximum braking without locking up wheels (required standard 3)</li><li>A4.5: stops aircraft within landing distance available (required standard 3)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Short field take off and landings Check essential knowledge from circuits and circuit emergency briefs Factors affecting take-off and landing performance and the distance required Factors affecting climb performance, missed approach performance and obstacle clearance Calculating headwind and crosswind components Calculating take-off and landing run and distance required</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Factors affecting length of take-off and landing run &amp; distance Contents of the flight manual and pilot operating handbook for the aircraft being flown [A1 4(g)] Relevant sections of the AIP [A1 4(n)] Aeroplane performance [A4 4(b)] Minimum equipment list [C2 4(c)]</li><li>HF &amp; NTS Effective communication under normal and non-normal circumstances [NTS1 4(a), NTS2 4(a)] Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)] Use of checklists and standard operating procedures to prevent errors [NTS2 4(h)] Task management [NTS2 4(i)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-22',
    'RPL(A)22',
    'Circuits - Short Field t/o & Landing',
    'flight',
    60,
    'Practice',
    ARRAY['Pre-flight actions and procedures - MEL, NOTAMs, GNSS (if applicable), ERSA, AIP', 'Circuits - ‘short field’ take-off and landing']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>22_RPL(A) Circuits - Short Field Take-off and Landing.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    22,
    'Consolidation',
    'Manage fuel system - fuel log, best endurance configuration, calculating endurance Revise: forced landing - simulated partial engine failure abnormal situations (e.g. simulated electrical failure) stalling, incipient spin Assess: ‘short field’ take-off and landing best angle climb steep turns, sideslipping recovery from unusual flight attitudes',
    '<p><strong>Lesson overview</strong></p><ul><li>Manage fuel system - fuel log, best endurance configuration, calculating endurance Revise: forced landing - simulated partial engine failure abnormal situations (e.g. simulated electrical failure) stalling, incipient spin Assess: ‘short field’ take-off and landing best angle climb steep turns, sideslipping recovery from unusual flight attitudes</li></ul><ul><li>C2.1: Pre-flight actions and procedures (MEL, NOTAM, GNSS RAIM information, ERSA, AIP)</li><li>C2.2: Perform pre-flight inspection</li><li>C2.2: report to, and seek advice from, qualified personnel to determine the action required in relation to any identified defects or damage (required standard 3)</li><li>C2.2: certify the aircraft flight technical log entering any defects or endorsements to permissible unserviceabilities as appropriate (required standard 3)</li><li>C2.2: complete and certify the daily inspection (if authorised to do so) (required standard 3)</li><li>C5.3: Manage cargo</li><li>C5.3: manage loading, unloading and security of cargo during flight operations (required standard 3)</li><li>C5.3: identify dangerous goods and apply procedures to ensure safety and security (required standard 3)</li><li>A2.5: Take off aeroplane from ‘short field’</li><li>A2.5: calculate take-off and landing performance in accordance with the aeroplane&#x27;s performance charts (required standard 2)</li><li>A2.5: perform take-off aeroplane to achieve the minimum length take-off performance (required standard 2)</li><li>A2.5: perform take-off aeroplane to achieve the obstacle clearance parameters (required standard 2)</li><li>A3.1: Climb aeroplane (best angle climb)</li><li>A5.1: Enter and recover from stall (revise incipient stall, stall with full power, climbing, descending, turning, simulated partial &amp; complete engine failure configurations)</li><li>A5.2: Recover from incipient spin</li><li>A5.3: Turn aeroplane steeply</li><li>A5.4: Sideslip aeroplane (where flight manual permits)</li><li>A6.3: Perform forced landing (simulated) (revise simulated partial engine failure)</li><li>A6.5: Manage other abnormal situations (simulated) (e.g. simulated electrical failure)</li><li>A6.6: Recover from unusual flight attitudes (nose-high and nose-low)</li><li>C4.2: Manage fuel system</li><li>C4.2: accurately maintain fuel log (required standard 3)</li><li>C4.2: calculate and state endurance at any point during flight (required standard 3)</li><li>C4.2: configure the aircraft correctly to achieve best endurance performance and correctly calculate the revised operational endurance (required standard 3)</li><li>A4.5: Short landing</li><li>A4.5: land aeroplane at nominated touchdown point at minimum speed (required standard 2)</li><li>A4.5: control ballooning during flare (required standard 2)</li><li>A4.5: control bouncing after touchdown (required standard 2)</li><li>A4.5: maintain direction after touchdown (required standard 2)</li><li>A4.5: apply maximum braking without locking up wheels (required standard 2)</li><li>A4.5: stops aircraft within landing distance available (required standard 2)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - as required</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Minimum equipment list [C2 4(c)], airworthiness requirements applicable to category, class or type [C2 4(d)] Characteristics of radio waves, wave propagation, transmission and reception [C3 4(d)(i)-(v)] Contents of the flight manual and pilot operating handbook for the aircraft being flown [A1 4(g), A4 4(g)] Relevant sections of the AIP [A1 4(n), A3 4(q), A4 4(k), A5 4(f)]</li><li>HF &amp; NTS Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)] Task management [NTS2 4(i)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-23',
    'RPL(A)23',
    'Consolidation',
    'flight',
    60,
    'Practice',
    ARRAY['Manage fuel system - fuel log, best endurance configuration, calculating endurance Revise: forced landing - simulated pa']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>23_RPL(A) Consolidation.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    23,
    'Precautionary Search & Landing',
    'Precautionary search & landing Fuel log, best endurance configuration, calculating endurance Abnormal situations (e.g. low fuel situation, deteriorating weather) Assess: Pre-flight actions and procedures - MEL, NOTAMs, GNSS (if applicable), ERSA, AIP ‘Short field’ take-off and landing',
    '<p><strong>Lesson overview</strong></p><ul><li>Precautionary search &amp; landing Fuel log, best endurance configuration, calculating endurance Abnormal situations (e.g. low fuel situation, deteriorating weather) Assess: Pre-flight actions and procedures - MEL, NOTAMs, GNSS (if applicable), ERSA, AIP ‘Short field’ take-off and landing</li></ul><ul><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: obtain, interpret and apply information contained in the required pre-flight operational documentation, including the following:</li><li>C2.1: minimum equipment list (MEL) (required standard 2)</li><li>C2.1: Notice to Airmen (NOTAM) (required standard 2)</li><li>C2.1: global navigation satellite system (GNSS) receiver autonomous integrity monitoring (RAIM) information (required standard 2)</li><li>C2.1: En Route Supplement Australia (ERSA) (required standard 2)</li><li>C2.1: Aeronautical Information Package (AIP) (required standard 2)</li><li>C2.2: Perform pre-flight inspection</li><li>C2.2: report to, and seek advice from, qualified personnel to determine the action required in relation to any identified defects or damage (required standard 3)</li><li>C2.2: certify the aircraft flight technical log entering any defects or endorsements to permissible unserviceabilities as appropriate (required standard 3)</li><li>C2.2: complete and certify the daily inspection (if authorised to do so) (required standard 3)</li><li>C5.3: Manage cargo</li><li>A2.5: Take off aeroplane from ‘short field’</li><li>A6.4: Conduct precautionary search and landing (simulated condition)</li><li>A6.4: assess flight circumstances and make an appropriate decision when to perform precautionary landing (required standard 3)</li><li>A6.4: configure aeroplane for conditions (required standard 3)</li><li>A6.4: perform precautionary search procedure (required standard 3)</li><li>A6.4: select landing area, carry out an inspection and assess its suitability for landing, taking into account:</li><li>A6.4: unobstructed approach and overshoot paths (required standard 3)</li><li>A6.4: landing area length adequate for landing (required standard 3)</li><li>A6.4: landing area surface is suitable for aeroplane type and clear of hazards (required standard 3)</li><li>A6.4: maintain orientation and visual contact with the landing area (required standard 3)</li><li>A6.4: advise ATS or other agencies capable of providing assistance of situation and intentions (required standard 3)</li><li>A6.4: re-brief passengers about flight situation, brace position and harness security (required standard 3)</li><li>A6.4: land and secure aircraft and manage passengers (required standard 3)</li><li>A6.5: Manage other abnormal situations (simulated) (e.g. low fuel situation, deteriorating weather)</li><li>C4.2: Manage fuel system (maintain fuel log, endurance calculations, configure for best endurance)</li><li>A4.5: Short landing</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.5 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Precautionary search &amp; landing Circumstances which may require a precautionary landing Importance of proper planning and early decision making Aeroplane configuration - precautionary/poor visibility cruise Landing area/field selection Obstacle, terrain and turbulence awareness Wind awareness - judging direction and strength Low flying considerations and hazards Turning illusions Planning the search, approach and landing Vital actions Radio procedures (PAN call) Passenger management Actions after landing</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Variations to planned fuel consumption [C4 4(h)] Contents of the aircraft flight manual and pilot’s operating handbook [A3 4(m), A4 4(g), A6 4(l)] Causes leading to precautionary landings [A6 4(c)] Suitable fields for forced landings and precautionary landings [A6 4(g)] Considerations when practising emergencies/ non-normal operations [A6 4(h)], Low flying hazards [A6 4(o)] VMC [A4 4(h), A6 4(n)], Day VFR flight rules [A4 4(i)]</li><li>HF &amp; NTS Effective communication under normal and non-normal circumstances [NTS1 4(a), NTS2 4(a)] Threat and error management detailing processes that can be used to identify and mitigate or control threats and errors [NTS2 4(b)] Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)] Task management [NTS2 4(i)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-24',
    'RPL(A)24',
    'Precautionary Search & Landing',
    'flight',
    60,
    'Practice',
    ARRAY['Precautionary search & landing', 'Fuel log, best endurance configuration, calculating endurance']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>24_RPL(A) Precautionary Search &amp; Landing.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    24,
    'Solo Consolidation',
    'Practice forced landing Basic stalls (entry from straight & level without power applied, approach to land configuration) Steep level turns Suggested flight time: 1.0 hour',
    '<p><strong>Lesson overview</strong></p><ul><li>Practice forced landing Basic stalls (entry from straight &amp; level without power applied, approach to land configuration) Steep level turns Suggested flight time: 1.0 hour</li></ul><ul><li>Practice forced landing Basic stalls (entry from straight &amp; level without power applied, approach to land configuration) Steep level turns Suggested flight time: 1.0 hour</li><li>Operational Limitations: During solo flight, trainees must only be authorised to practise sequences that have been assessed to performance standard 2 or 1, on a minimum of two separate flights. Except in emergency or urgency situations, or in the interests of maintaining safety, the trainee must not operate contrary to the limitations and guidelines specified by the authorising flight instructor.</li></ul>',
    '<ul><li>Operational Limitations: During solo flight, trainees must only be authorised to practise sequences that have been assessed to performance standard 2 or 1, on a minimum of two separate flights. Except in emergency or urgency situations, or in the interests of maintaining safety, the trainee must not operate contrary to the limitations and guidelines specified by the authorising flight instructor.</li></ul>',
    'casa-rpl-a-25',
    'RPL(A)25',
    'Solo Consolidation',
    'flight',
    60,
    'Practice',
    ARRAY['Practice forced landing', 'Basic stalls (entry from straight & level without power applied, approach to land configuration)', 'Steep level turns', 'Suggested flight time: 1.0 hour']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>25_RPL(A) Solo Consolidation.DOCX</li></ul><ul><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    25,
    'Basic Instrument Flight',
    'Basic instrument flight Recognition of and recovery from upset situations and unusual attitudes Actions upon inadvertent entry into IMC Assess: communicating face-to-face pre-flight actions and procedures, pre-flight inspection start and stop engine taxiing pre-take off procedures operational communication, operate radio equipment, operate transponder post-flight actions and procedures',
    '<p><strong>Lesson overview</strong></p><ul><li>Basic instrument flight Recognition of and recovery from upset situations and unusual attitudes Actions upon inadvertent entry into IMC Assess: communicating face-to-face pre-flight actions and procedures, pre-flight inspection start and stop engine taxiing pre-take off procedures operational communication, operate radio equipment, operate transponder post-flight actions and procedures</li></ul><ul><li>C1.1: Communicating face-to-face</li><li>C1.1: pronounces words clearly, using an accent that does not cause difficulties in understanding (required standard 1)</li><li>C1.1: conveys information in clearly structured sentences without confusion or ambiguity (required standard 1)</li><li>C1.1: uses an extensive vocabulary to accurately communicate on general and technical topics, without excessive use of jargon, slang or colloquial language (required standard 1)</li><li>C1.1: speaks fluently without long pauses, repetition or excessive false starts (required standard 1)</li><li>C1.1: responds to communications with actions that demonstrate that the information has been received and understood (required standard 1)</li><li>C1.1: exchanges information clearly in a variety of situations with both expert and non-expert English speakers while giving and receiving timely and appropriate responses (required standard 1)</li><li>C1.1: uses appropriate techniques to validate communications (required standard 1)</li><li>C1.2: Operational communication using an aeronautical radio</li><li>C1.2: maintain effective communication with others on operational matters (required standard 1)</li><li>C1.2: communicate effectively in unfamiliar, stressful or non-standard situations (required standard 1)</li><li>C1.2: apply the phonetic alphabet (required standard 1)</li><li>C1.2: transmit numbers (required standard 1)</li><li>C1.2: make appropriate transmissions using standard aviation phraseology (required standard 1)</li><li>C1.2: use plain English effectively when standard phraseology is inadequate (required standard 1)</li><li>C1.2: receive appropriate responses to transmissions (required standard 1)</li><li>C1.2: respond to transmissions and take appropriate action (required standard 1)</li><li>C1.2: recognise and manage communication errors and misunderstandings effectively (required standard 1)</li><li>C1.2: seek clarification in the time available if a message is unclear or uncertainty exists (required standard 1)</li><li>C1.2: react appropriately to a variety of regional accents (required standard 1)</li><li>C1.2: communicate effectively in unexpected, stressful or non-standard situations using standard phraseology or plain English (required standard 1)</li><li>C2.1: Pre-flight actions and procedures</li><li>C2.1: complete all required pre-flight administration documentation (required standard 1)</li><li>C2.1: obtain, interpret and apply information contained in the required pre-flight operational documentation, including the following:</li><li>C2.1: minimum equipment list (MEL) (required standard 1)</li><li>C2.1: maintenance release (required standard 1)</li><li>C2.1: weather forecasts (required standard 1)</li><li>C2.1: local observations (required standard 1)</li><li>C2.1: Notice to Airmen (NOTAM) (required standard 1)</li><li>C2.1: global navigation satellite system (GNSS) receiver autonomous integrity monitoring (RAIM) information (required standard 1)</li><li>C2.1: En Route Supplement Australia (ERSA) (required standard 1)</li><li>C2.1: Aeronautical Information Package (AIP) (required standard 1)</li><li>C2.1: identify special aerodrome procedures (required standard 1)</li><li>C2.1: identify all relevant radio and navigation aid facilities to be used during the flight (if applicable) (required standard 1)</li><li>C2.1: determine the suitability of the current and forecast weather conditions for the proposed flight (required standard 1)</li><li>C2.1: using the aircraft documents, calculate the following for a given set of environmental and operational conditions:</li><li>C2.1: weight and balance (required standard 1)</li><li>C2.1: take-off and landing performance (required standard 1)</li><li>C2.1: fuel requirements (required standard 1)</li><li>C2.1: determine whether the aircraft is serviceable for the proposed flight (required standard 1)</li><li>C2.2: Perform pre-flight inspection</li><li>C2.2: identify and secure equipment and documentation that is required for the flight (required standard 1)</li><li>C2.2: complete an internal and external check of the aircraft (required standard 1)</li><li>C2.2: identify all defects or damage to the aircraft (required standard 1)</li><li>C2.2: report to, and seek advice from, qualified personnel to determine the action required in relation to any identified defects or damage (required standard 1)</li><li>C2.2: ensure all aircraft locking and securing devices, covers and bungs are removed and stowed securely (required standard 1)</li><li>C2.2: certify the aircraft flight technical log entering any defects or endorsements to permissible unserviceabilities as appropriate (required standard 1)</li><li>C2.2: complete and certify the daily inspection (if authorised to do so) (required standard 1)</li><li>A1.1: Start and stop engine</li><li>A1.1: perform engine start and after start actions (required standard 1)</li><li>A1.1: perform engine shutdown and after shutdown actions (required standard 1)</li><li>A1.1: manage engine start and shutdown malfunctions and emergencies (required standard 1)</li><li>A1.1: considers ground surface in relation to contamination and propeller care during engine start and stop activities (required standard 1)</li><li>A1.2: Taxi aeroplane</li><li>A1.2: use aerodrome or landing area charts to taxi aircraft (required standard 1)</li><li>A1.2: comply with taxiway and other aerodrome markings, right-of-way rules and ATC or marshalling instructions when applicable (required standard 1)</li><li>A1.2: perform applicable taxi checks, including the following:</li><li>A1.2: brakes and steering function normally and take appropriate action in the event of a malfunction (required standard 1)</li><li>A1.2: instruments for correct readings (required standard 1)</li><li>A1.2: altimeter setting (required standard 1)</li><li>A1.2: maintain safe taxi speed and control of the aircraft (required standard 1)</li><li>A1.2: maintain safe spacing from other aircraft, obstructions, and persons (required standard 1)</li><li>A1.2: taxi the aeroplane along the centre of the taxiway (required standard 1)</li><li>A1.2: avoid causing a hazard to other aircraft, objects or persons (required standard 1)</li><li>A1.2: correct handling techniques are applied to take into account wind from all four quadrants (required standard 1)</li><li>A1.2: correctly manage the engine during taxi manoeuvres (required standard 1)</li><li>A2.1: Carry out pre take-off procedures</li><li>A2.1: correctly identify critical airspeeds, configurations, and emergency and abnormal procedures for normal and crosswind take-offs (required standard 1)</li><li>A2.1: work out a plan of action, in advance, to ensure the safest outcome in the event of abnormal operations (required standard 1)</li><li>A2.1: verify and correctly apply correction for the existing wind component to the take-off performance (required standard 1)</li><li>A2.1: perform all pre take-off and line-up checks required by the aircraft checklist (required standard 1)</li><li>A2.1: ensure approach path is clear of conflicting traffic and other hazards before lining up for take-off (required standard 1)</li><li>A2.1: align the aeroplane on the runway centreline (required standard 1)</li><li>C3.1: Operate radio equipment</li><li>C3.1: confirm serviceability of radio equipment (required standard 1)</li><li>C3.1: conduct transmission and receipt of radio communications using appropriate procedures and phraseology (required standard 1)</li><li>C3.1: maintain a listening watch and respond appropriately to applicable transmissions (required standard 1)</li><li>C3.1: conduct appropriate emergency and urgency transmissions (required standard 1)</li><li>C3.3: Operate transponder</li><li>C3.3: operate a transponder during normal, abnormal and emergency operations (required standard 1)</li><li>C3.3: recall transponder emergency codes (required standard 1)</li><li>IFF.1: Determine and monitor the serviceability of flight instruments and instrument power sources</li><li>IFF.1: determine serviceability of flight and navigational instruments (required standard 3)</li><li>IFF.1: perform functional checks of flight and navigational instruments where applicable prior to take-off (required standard 3)</li><li>IFF.1: monitor flight instrument and instrument power sources and react to any warnings, unserviceability or erroneous indications (required standard 3)</li><li>IFF.2: Perform manoeuvres using full instrument panel</li><li>IFF.2: interpret flight instrument indications and apply procedures and techniques to achieve and maintain a specified flight path using the aircraft&#x27;s full instrument panel (required standard 3)</li><li>IFF.2: set and maintain power and attitude by reference to the full instrument panel to establish a rate 1 turn onto a nominated heading within the flight tolerances (required standard 3)</li><li>IFF.3: Recover from upset situations and unusual attitudes</li><li>IFF.3: correctly identify upset situations and unusual attitudes under simulated IMC (required standard 3)</li><li>IFF.3: recover to controlled flight from upset situations and unusual attitudes under simulated IMC from any combination of the following aircraft states:</li><li>IFF.3: high and low-nose attitudes (required standard 3)</li><li>IFF.3: varying angles of bank (required standard 3)</li><li>IFF.3: various power settings (required standard 3)</li><li>IFF.3: various aircraft configurations (required standard 3)</li><li>IFF.3: unbalanced flight (required standard 3)</li><li>C2.3: Post-flight actions and procedures</li><li>C2.3: shut down aircraft (required standard 1)</li><li>C2.3: conduct post-flight inspection and secure the aircraft (if applicable) (required standard 1)</li><li>C2.3: complete all required post-flight administration documentation (required standard 1)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: 0.8 hour Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Basic instrument flight Instrument power sources Instrument checks &amp; serviceability Control and performance instruments Instrument lag Sensory illusions Scan technique Dangers associated with attempting VFR flight into deteriorating weather Importance of proper pre-flight preparation and planning to avoid inadvertent entry into IMC Actions upon inadvertent entry into IMC Compass turning and acceleration errors Unusual attitudes - instrument indications, recovery techniques</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required Scan technique appropriate to fitted flight instruments and phase of flight [IFF 4(a)] Attitude and power requirements to achieve specified flight profiles [IFF 4(b)] Instrument failure and warning systems fitted to the aeroplane [IFF 4(c)] Turning using a magnetic compass [A3 4(h)] Environmental conditions that represent VMC [A4 4(h), A5 4(d)], Day VFR flight rules [A4 4(i), A5 4(e)]</li><li>HF &amp; NTS Threat and error management detailing processes that can be used to identify and mitigate or control threats and errors [NTS2 4(b)] The application of situational awareness to identifying real or potential environmental or operational threats to flight safety [NTS2 4(c)] Developing and implementing plans of action for the following [NTS2 4(d)]: removing and mitigating threats removing and mitigating errors Undesired aeroplane state - prevention, identifying, controlling [NTS2 4(e)] How an undesired aeroplane state can develop from unmanaged threat or error [NTS2 4(f)]</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-26',
    'RPL(A)26',
    'Basic Instrument Flight',
    'flight',
    60,
    'Practice',
    ARRAY['Basic instrument flight', 'Recognition of and recovery from upset situations and unusual attitudes']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>26_RPL(A) Basic Instrument Flight.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    26,
    'Consolidation',
    'Consolidation: basic instrument flight, including actions in event of inadvertent entry into IMC forced landing - simulated complete engine failure precautionary search and landing abnormal situations - unreliable airspeed indication ‘short field’ landing Assess: communicating face-to-face plan fuel requirements, refuelling, manage fuel system pre-flight actions and procedures, pre-flight inspection start and stop engine taxiing pre-take off procedures simulated engine failure on take-off operational communication, operate radio equipment, operate transponder climbing, straight and level, descending, turning local area airspace post-flight actions and procedures Flight manoeuvres to be performed within the flight tolerances mentioned in Schedule 8 of the Part 61 MOS',
    '<p><strong>Lesson overview</strong></p><ul><li>Consolidation: basic instrument flight, including actions in event of inadvertent entry into IMC forced landing - simulated complete engine failure precautionary search and landing abnormal situations - unreliable airspeed indication ‘short field’ landing Assess: communicating face-to-face plan fuel requirements, refuelling, manage fuel system pre-flight actions and procedures, pre-flight inspection start and stop engine taxiing pre-take off procedures simulated engine failure on take-off operational communication, operate radio equipment, operate transponder climbing, straight and level, descending, turning local area airspace post-flight actions and procedures Flight manoeuvres to be performed within the flight tolerances mentioned in Schedule 8 of the Part 61 MOS</li></ul><ul><li>C1.1: Communicating face-to-face</li><li>C1.2: Operational communication using an aeronautical radio</li><li>C2.1: Pre-flight actions and procedures</li><li>C4.1: Plan fuel requirements</li><li>C4.1: determine the required fuel reserves (required standard determine the required fuel reserves)</li><li>C4.1: determine the quantity of fuel required taking into account operational requirements and relevant abnormal or emergency conditions and contingencies (required standard determine the quantity of fuel required taking into account operational requirements and relevant abnormal or emergency conditions and contingencies)</li><li>C4.1: determine the total fuel required for the flight (required standard determine the total fuel required for the flight)</li><li>C4.2: Manage fuel system</li><li>C4.2: verify fuel quantity on-board aircraft prior to flight using two independent methods (required standard verify fuel quantity on-board aircraft prior to flight using two independent methods)</li><li>C4.2: ensure the fuel caps are secured (required standard ensure the fuel caps are secured)</li><li>C4.2: perform fuel quality check prior to flight (required standard perform fuel quality check prior to flight)</li><li>C4.2: ensure fuel drain cocks are closed (required standard ensure fuel drain cocks are closed)</li><li>C4.2: monitor fuel usage during the flight (required standard monitor fuel usage during the flight)</li><li>C4.2: accurately maintain fuel log (required standard accurately maintain fuel log)</li><li>C4.2: calculate and state endurance at any point during flight (required standard calculate and state endurance at any point during flight)</li><li>C4.2: perform fuel tank changes correctly (required standard perform fuel tank changes correctly)</li><li>C4.2: maintain fuel load within aircraft limits (required standard maintain fuel load within aircraft limits)</li><li>C4.2: operate the fuel cross-feed system correctly (if fitted) (required standard operate the fuel cross-feed system correctly (if fitted))</li><li>C4.2: operate fuel pumps and engine controls correctly (required standard operate fuel pumps and engine controls correctly)</li><li>C4.2: configure the aircraft correctly to achieve best endurance performance and correctly calculate the revised operational endurance (required standard configure the aircraft correctly to achieve best endurance performance and correctly calculate the revised operational endurance)</li><li>C4.3: Refuel aircraft</li><li>C4.3: identify the correct type of fuel to be used (required standard identify the correct type of fuel to be used)</li><li>C4.3: ensure aircraft is earthed prior to refuelling and defueling operations (required standard ensure aircraft is earthed prior to refuelling and defueling operations)</li><li>C4.3: correctly load and unload fuel (required standard correctly load and unload fuel)</li><li>C4.3: ensure required fuel quantity is loaded (required standard ensure required fuel quantity is loaded)</li><li>C4.3: ensure fuel caps are closed and secured after fuelling operations (required standard ensure fuel caps are closed and secured after fuelling operations)</li><li>C4.3: perform fuel quality checks (required standard perform fuel quality checks)</li><li>C2.2: Perform pre-flight inspection</li><li>A1.1: Start and stop engine</li><li>A1.2: Taxi aeroplane</li><li>A2.1: Carry out pre take-off procedures</li><li>A6.1: Manage engine failure - take-off (simulated)</li><li>A6.1: correctly identify an engine failure after take-off (required standard correctly identify an engine failure after take-off)</li><li>A6.1: apply the highest priority to taking action to control the aeroplane (required standard apply the highest priority to taking action to control the aeroplane)</li><li>A6.1: maintain control of the aeroplane (required standard maintain control of the aeroplane)</li><li>A6.1: perform recall actions (required standard perform recall actions)</li><li>A6.1: perform emergency actions as far as time permits (required standard perform emergency actions as far as time permits)</li><li>A6.1: manoeuvre the aeroplane to achieve the safest possible outcome (required standard manoeuvre the aeroplane to achieve the safest possible outcome)</li><li>A6.1: ensure passengers adopt brace position (required standard ensure passengers adopt brace position)</li><li>A6.1: advise others such as ATS and other aircraft of intentions if time permits (required standard advise others such as ATS and other aircraft of intentions if time permits)</li><li>A3.1: Climb aeroplane</li><li>A3.1: operate and monitor all aircraft systems when commencing, during, and completing a climbing flight manoeuvre (required standard operate and monitor all aircraft systems when commencing, during, and completing a climbing flight manoeuvre)</li><li>A3.1: adjust altimeter subscale according to applicable settings (required standard adjust altimeter subscale according to applicable settings)</li><li>A3.1: identify and avoid terrain and traffic (required standard identify and avoid terrain and traffic)</li><li>A3.1: for the following climbing manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre: (required standard for the following climbing manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:)</li><li>A3.1: cruise climb (required standard cruise climb)</li><li>A3.1: best angle climb (required standard best angle climb)</li><li>A3.1: best rate climb (required standard best rate climb)</li><li>A3.1: anticipate level-off altitude and achieve straight and level flight (required standard anticipate level-off altitude and achieve straight and level flight)</li><li>A3.2: A3.2</li><li>A3.2: operate and monitor all aircraft systems during straight and level flight manoeuvres (required standard operate and monitor all aircraft systems during straight and level flight manoeuvres)</li><li>A3.2: adjust altimeter subscale according to applicable settings (required standard adjust altimeter subscale according to applicable settings)</li><li>A3.2: identify and avoid terrain and traffic (required standard identify and avoid terrain and traffic)</li><li>A3.2: for the following straight and level manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre: (required standard for the following straight and level manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:)</li><li>A3.2: at slow speed (required standard at slow speed)</li><li>A3.2: at normal cruise (required standard at normal cruise)</li><li>A3.2: at high-speed cruise (required standard at high-speed cruise)</li><li>A3.2: during acceleration and deceleration (required standard during acceleration and deceleration)</li><li>A3.2: with flaps selected (required standard with flaps selected)</li><li>A3.4: A3.4</li><li>A3.4: operate and monitor all aircraft systems during turning flight manoeuvres (required standard operate and monitor all aircraft systems during turning flight manoeuvres)</li><li>A3.4: for the following turning manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre: (required standard for the following turning manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:)</li><li>A3.4: level turns (required standard level turns)</li><li>A3.4: climbing turns (required standard climbing turns)</li><li>A3.4: powered descending turns (required standard powered descending turns)</li><li>A3.4: gliding descending turns (required standard gliding descending turns)</li><li>A3.4: complete turn manoeuvre on a nominated heading or geographical feature (required standard complete turn manoeuvre on a nominated heading or geographical feature)</li><li>A3.4: turn aeroplane at varying rates to achieve specified tracks (required standard turn aeroplane at varying rates to achieve specified tracks)</li><li>A3.4: manoeuvre aeroplane over specified tracks or geographical features (required standard manoeuvre aeroplane over specified tracks or geographical features)</li><li>C3.1: Operate radio equipment</li><li>C3.3: Operate transponder</li><li>A3.7: Local area airspace</li><li>A3.7: using an appropriate chart, for the local area and circuit area: (required standard using an appropriate chart, for the local area and circuit area:)</li><li>A3.7: identify geographical features (required standard identify geographical features)</li><li>A3.7: identify geographical limits (required standard identify geographical limits)</li><li>A3.7: identify restricted, controlled and uncontrolled airspace areas (required standard identify restricted, controlled and uncontrolled airspace areas)</li><li>A3.7: state local airspace limits (required standard state local airspace limits)</li><li>A3.7: identify the transit route between the departure aerodrome and training area (required standard identify the transit route between the departure aerodrome and training area)</li><li>A3.7: identify the geographical limits of the training area (required standard identify the geographical limits of the training area)</li><li>A3.7: identify aerodromes and landing areas within the local area (required standard identify aerodromes and landing areas within the local area)</li><li>A3.7: maintain orientation and pinpoint location by using geographical features and a local area chart (required standard maintain orientation and pinpoint location by using geographical features and a local area chart)</li><li>A3.7: transit from the circuit area and transit to the designated training area (required standard transit from the circuit area and transit to the designated training area)</li><li>A3.7: operate safely within a transit lane (if applicable) (required standard operate safely within a transit lane (if applicable))</li><li>A3.7: remain clear of restricted, controlled and other appropriately designated airspace (required standard remain clear of restricted, controlled and other appropriately designated airspace)</li><li>A3.7: operate safely in the vicinity of local aerodromes and landing areas (required standard operate safely in the vicinity of local aerodromes and landing areas)</li><li>A3.7: transit from the designated training area to the circuit area (required standard transit from the designated training area to the circuit area)</li><li>A3.7: set QNH appropriately (required standard set QNH appropriately)</li><li>A3.7: correctly determine which runway is to be used for landing (required standard correctly determine which runway is to be used for landing)</li><li>A3.7: ensure runway is serviceable and available (required standard ensure runway is serviceable and available)</li><li>A3.7: position aircraft for arrival into the circuit (required standard position aircraft for arrival into the circuit)</li><li>A6.3: Perform forced landing (simulated)</li><li>A6.4: Conduct precautionary search and landing (simulated condition)</li><li>A6.5: Manage other abnormal situations (simulated</li><li>A6.5: identify and conduct flight with an unreliable airspeed indication (required standard identify and conduct flight with an unreliable airspeed indication)</li><li>IFF.1: Determine and monitor the serviceability of flight instruments and instrument power sources</li><li>IFF.2: Perform manoeuvres using full instrument panel</li><li>IFF.3: Recover from upset situations and unusual attitudes</li><li>A3.3: A3.3</li><li>A3.3: operate and monitor all aircraft systems during descending flight manoeuvres (required standard operate and monitor all aircraft systems during descending flight manoeuvres)</li><li>A3.3: for the following descending manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre: (required standard for the following descending manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:)</li><li>A3.3: glide (required standard glide)</li><li>A3.3: powered (required standard powered)</li><li>A3.3: approach configuration descent (flap and undercarriage) (required standard approach configuration descent (flap and undercarriage))</li><li>A3.3: anticipate level-off altitude and achieve straight and level flight (required standard anticipate level-off altitude and achieve straight and level flight)</li><li>A4.5: Short landing</li><li>C2.3: Post-flight actions and procedures</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing - Revision as required</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required</li><li>HF &amp; NTS Review as required</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Theory examinations The RPLA Aeronautical Knowledge Examination should be passed prior to lesson RPL(A)29, and must be passed prior to the RPL(A) flight test. The RPL Flight Radio Operator Examination should be passed prior to the RPL(A) flight test, and must be passed prior to the issue of the RPL flight radio endorsement. The trainee must also hold a current aviation English language proficiency assessment for the issue of the RPL flight radio endorsement. Where the trainee achieves a pass of less than 100% in the above examinations, a knowledge deficiency report (KDR) assessment is to be conducted by an authorised flight instructor</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-27',
    'RPL(A)27',
    'Consolidation',
    'flight',
    60,
    'Practice',
    ARRAY['Flight manoeuvres to be performed within the flight tolerances mentioned in', 'Schedule 8 of the', 'Part 61 MOS']::text[],
    'Review lesson briefing, required pre-flight knowledge and any carryover items from the previous lesson.',
    '<p><strong>Source document</strong></p><ul><li>27_RPL(A) Consolidation.DOCX</li></ul><ul><li>DEBRIEFING</li><li>Content</li><li>Training review and outcomes achieved against lesson objectives and the Part 61 MOS competency standards Recommendations for next lesson (including any carryover/remedial training) Trainee preparation for next lesson Training record completion and sign off</li><li>COMMENTS AND OUTCOME | COMMENTS AND OUTCOME | COMMENTS AND OUTCOME</li><li>Proceed to next training session? | Yes | No</li></ul>',
    '[]'::jsonb,
    '{"casa-rpl-performance-standard": "Pass", "casa-rpl-hf-nts": "Pass", "casa-rpl-knowledge": "Pass"}'::jsonb,
    false
  );

  INSERT INTO public.training_lessons (
    course_id, sort_order, name, objective, flight_exercises, theory,
    sequence_id, sequence_code, sequence_title, stage, duration_minutes,
    min_competency, key_exercises, student_preparation, instructor_notes,
    assessment_criteria, pass_marks, is_flight_test
  ) VALUES (
    v_course_id,
    27,
    'Consolidation',
    'Consolidate and assess: plan fuel requirements, refuelling, manage fuel system simulated engine failure on take-off radio failure procedures local area airspace take-offs, circuits, landings (including missed approach and missed landing) simulated engine failure in circuit area precautionary search and landing climbing, turning, descending forced landing - simulated complete and partial engine failures slow flight, stalling, incipient spin steep turns, sideslipping unusual flight attitude recoveries basic instrument flight manage and assist passengers, manage cargo non-technical skills Flight manoeuvres to be performed within the flight tolerances mentioned in Table 1, Schedule 8 of the Part 61 MOS',
    '<p><strong>Lesson overview</strong></p><ul><li>Consolidate and assess: plan fuel requirements, refuelling, manage fuel system simulated engine failure on take-off radio failure procedures local area airspace take-offs, circuits, landings (including missed approach and missed landing) simulated engine failure in circuit area precautionary search and landing climbing, turning, descending forced landing - simulated complete and partial engine failures slow flight, stalling, incipient spin steep turns, sideslipping unusual flight attitude recoveries basic instrument flight manage and assist passengers, manage cargo non-technical skills Flight manoeuvres to be performed within the flight tolerances mentioned in Table 1, Schedule 8 of the Part 61 MOS</li></ul><ul><li>C4.1: Plan fuel requirements</li><li>C4.3: Refuel aircraft</li><li>C4.2: Manage fuel system</li><li>C5.1: Manage passengers</li><li>C5.1: supervise passenger safety (required standard 1)</li><li>C5.1: encourage passengers to participate in and contribute to the safe outcome of the flight (required standard 1)</li><li>C5.1: conduct pre-flight passenger safety briefing (required standard 1)</li><li>C5.1: ensure passengers are aware of, and avoid interference with, flight and systems controls (required standard 1)</li><li>C5.1: ensure passengers are aware of, and comply with, the use of seat harnesses (required standard 1)</li><li>C5.1: ensure passengers are aware of the use of escape hatches, exits and emergency equipment on board the aircraft (required standard 1)</li><li>C5.1: manage passenger safety in the event of abnormal or in-flight emergency situations (required standard 1)</li><li>C5.2: Aid and assist passengers</li><li>C5.2: establish and maintain clear communications with passengers (required standard 1)</li><li>C5.2: assist with passenger comfort both when airside and in flight (required standard 1)</li><li>C5.3: Manage cargo</li><li>C5.3: manage loading, unloading and security of cargo during flight operations (required standard 1)</li><li>C5.3: identify dangerous goods and apply procedures to ensure safety and security (required standard 1)</li><li>A2.2: Take off aeroplane</li><li>A2.2: apply the controls correctly to maintain longitudinal alignment on the centreline of the runway, if appropriate, prior to initiating and during the take-off (required standard 1)</li><li>A2.2: adjust the power controls taking into account the existing conditions (required standard 1)</li><li>A2.2: monitor power controls, settings, and instruments during take-off to ensure all predetermined parameters are achieved and maintained (required standard 1)</li><li>A2.2: adjust the controls to attain the desired pitch attitude at the predetermined airspeed to attain the desired performance (required standard 1)</li><li>A2.2: perform the take-off applying the required pitch, roll and yaw inputs as appropriate in a smooth, coordinated manner (required standard 1)</li><li>A2.2: trim the aeroplane accurately (required standard 1)</li><li>A2.2: perform gear and flap retractions, power adjustments (as applicable) and other required pilot-related activities (required standard 1)</li><li>A2.2: maintain flight path along the runway extended centreline (required standard 1)</li><li>A2.2: apply the applicable noise abatement and wake turbulence avoidance procedures (required standard 1)</li><li>A2.2: recognise take-off abnormalities and take appropriate action to reject take-off (can be simulated) (required standard 1)</li><li>A2.3: Take off aeroplane in a crosswind</li><li>A2.3: perform a take-off in an aeroplane making appropriate adjustments for the crosswind conditions (required standard 1)</li><li>A2.3: maintain the runway centreline and extended centreline (required standard 1)</li><li>A2.5: Take off aeroplane from ‘short field’</li><li>A2.5: calculate take-off and landing performance in accordance with the aeroplane&#x27;s performance charts (required standard 1)</li><li>A2.5: perform take-off aeroplane to achieve the minimum length take-off performance (required standard 1)</li><li>A2.5: perform take-off aeroplane to achieve the obstacle clearance parameters (required standard 1)</li><li>A6.1: Manage engine failure - take-off (simulated)</li><li>A2.4: Carry out after take-off procedures</li><li>A2.4: perform after take-off checklist (required standard 1)</li><li>A2.4: maintain the appropriate climb segment at the nominated heading and airspeed (required standard 1)</li><li>A2.4: manoeuvre according to local and standard procedures (required standard 1)</li><li>A2.4: maintain traffic separation (required standard 1)</li><li>A3.1: Climb aeroplane</li><li>A3.2: Maintain straight and level flight</li><li>A3.4: Turn aeroplane</li><li>A3.7: Local area airspace</li><li>A3.5: Control aeroplane at slow speeds</li><li>A3.5: complete pre-manoeuvre checks (required standard 1)</li><li>A3.5: operate and monitor all aircraft systems when operating the aeroplane at slow speed (required standard 1)</li><li>A3.5: for the following climbing manoeuvres select power, attitude and configuration as required for the flight path, balance and trim the aeroplane accurately, and apply smooth, coordinated control inputs to achieve the required flight tolerances that apply to the manoeuvre:</li><li>A3.5: minimum approach speed with flaps retracted (required standard 1)</li><li>A3.5: minimum approach speed in approach configuration (required standard 1)</li><li>A3.5: observe audible and visual stall warnings and recover aeroplane to controlled flight (required standard 1)</li><li>A3.5: recognise and respond positively to reduced effectiveness of controls during slow flight manoeuvres (required standard 1)</li><li>A3.5: transition from slow speed configuration using take-off power to achieve nominated speed in excess of 1.5 Vs without loss of height (required standard 1)</li><li>A5.1: Enter and recover from stall</li><li>A5.1: perform pre-manoeuvre checks for stalling (required standard 1)</li><li>A5.1: recognise stall signs and symptoms (required standard 1)</li><li>A5.1: control the aeroplane by applying the required pitch, roll and yaw inputs as appropriate in a smooth, coordinated manner, trim aeroplane accurately to enter and recover from the following manoeuvres:</li><li>A5.1: incipient stall (required standard 1)</li><li>A5.1: stall with full power applied (required standard 1)</li><li>A5.1: stall without power applied (required standard 1)</li><li>A5.1: stall under the following conditions: (required standard 1)</li><li>A5.1: (A) straight and level flight (required standard 1)</li><li>A5.1: (B) climbing (required standard 1)</li><li>A5.1: (C) descending (required standard 1)</li><li>A5.1: (D) approach to land configuration (required standard 1)</li><li>A5.1: (E) turning (required standard 1)</li><li>A5.1: perform stall recovery as follows:</li><li>A5.1: positively reduce angle of attack (required standard 1)</li><li>A5.1: use power available and excess height to increase the aircraft energy state (required standard 1)</li><li>A5.1: minimise height loss for simulated low altitude condition (required standard 1)</li><li>A5.1: re-establish desired flight path and aircraft control (required standard 1)</li><li>A5.1: recover from stall in simulated partial and complete engine failure configurations (required standard 1)</li><li>A5.2: Recover from incipient spin</li><li>A5.2: perform pre-manoeuvre checks for an incipient spin (required standard 1)</li><li>A5.2: recognise an incipient spin (required standard 1)</li><li>A5.2: use the aeroplane&#x27;s attitude and power controls to execute an incipient spin manoeuvre from the following flight conditions and, using correct recovery technique, regain straight and level flight with height loss commensurate with the available altitude (simulated ground base height may be set):</li><li>A5.2: straight and level flight (required standard 1)</li><li>A5.2: climbing (required standard 1)</li><li>A5.2: turning (required standard 1)</li><li>A5.3: Turn aeroplane steeply</li><li>A5.3: pre-manoeuvre checks for steep turning (required standard 1)</li><li>A5.3: steep level turn using a nominated bank angle, ending on a nominated heading or geographical feature, without altitude change (required standard 1)</li><li>A5.3: steep descending turn using a nominated bank angle, ending on a nominated heading or geographical feature ending on a nominated altitude (required standard 1)</li><li>A5.3: aeroplane operating limits are not exceeded (required standard 1)</li><li>A5.4: Sideslip aeroplane (where flight manual permits)</li><li>A5.4: straight sideslip:</li><li>A5.4: induce slip to achieve increased rate of descent while maintaining track and airspeed (required standard 1)</li><li>A5.4: adjust rate of descent by coordinating angle of bank and applied rudder (required standard 1)</li><li>A5.4: sideslipping turn by adjusting the bank angle to turn through minimum heading change of 90° at constant airspeed using sideslip, and exiting the turn on a specified heading or geographical feature, within tolerance (required standard 1)</li><li>A5.4: recover from a sideslip and return the aeroplane to balanced flight (required standard 1)</li><li>A6.6: Recover from unusual flight attitudes</li><li>A6.6: identify nose-high or nose-low unusual attitude flight condition (required standard 1)</li><li>A6.6: recover from nose-low or nose-high unusual attitudes by adjusting pitch, bank and power to resume controlled and balanced flight (required standard 1)</li><li>A6.6: apply controlled corrective action while maintaining aircraft performance within limits (required standard 1)</li><li>A6.3: Perform forced landing (simulated)</li><li>A6.3: after a simulated complete engine failure has occurred, without prior indications, carry out the following:</li><li>A6.3: identify complete power failure condition and control aeroplane (required standard 1)</li><li>A6.3: perform immediate actions (required standard 1)</li><li>A6.3: formulate and describe a recovery plan, including selecting the most suitable landing area (required standard 1)</li><li>A6.3: establish optimal gliding flight path to position the aeroplane for a landing on the selected landing area (required standard 1)</li><li>A6.3: perform emergency procedures and land the aeroplane if the engine cannot be restarted as time permits (required standard 1)</li><li>A6.3: advise ATS or other agencies capable of providing assistance of situation and intentions (required standard 1)</li><li>A6.3: re-brief passengers about flight situation, brace position and harness security (required standard 1)</li><li>A6.3: land the aeroplane ensuring safest outcome if an engine restart is not achieved (required standard 1)</li><li>A6.3: after a simulated partial engine failure has occurred, without prior indications, carry out the following:</li><li>A6.3: identify partial power failure condition (required standard 1)</li><li>A6.3: perform recall actions (required standard 1)</li><li>A6.3: adjust flight controls to re-establish flight path that maximises performance for partial power condition and maintain a safe airspeed margin above stall speed (required standard 1)</li><li>A6.3: establish radio communications where possible (required standard 1)</li><li>A6.3: perform partial engine failure actions (required standard 1)</li><li>A6.3: formulate a plan to recover aeroplane to a safe landing area or aerodrome, taking into account that partial failure might lead to a full power failure at any time (required standard 1)</li><li>A6.3: manoeuvre the aeroplane to a selected landing area or aerodrome using the remaining power to establish an optimal aircraft position for a safe landing (required standard 1)</li><li>A6.3: advise ATS or other agencies capable of providing assistance of situation and intentions (required standard 1)</li><li>A6.3: re-brief passengers about flight situation, brace position and harness security (required standard 1)</li><li>A6.3: maintain a contingency plan for coping with a full power failure throughout the manoeuvre (required standard 1)</li><li>A6.3: when a safe landing position is established, shut down and secure engine and aeroplane (required standard 1)</li><li>A6.4: Conduct precautionary search and landing (simulated condition)</li><li>A6.4: assess flight circumstances and make an appropriate decision when to perform precautionary landing (required standard 1)</li><li>A6.4: configure aeroplane for conditions (required standard 1)</li></ul>',
    '<ul><li>PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required PRE-FLIGHT KNOWLEDGE Long Briefing: as required Pre-flight Briefing: 0.3 hour Underpinning knowledge: as required</li><li>Long briefing Revision as required</li><li>Underpinning knowledge Review/expand previously introduced knowledge as required</li><li>HF &amp; NTS Review as required</li><li>Pre-flight briefing Review flight sequences, what to expect, see &amp; do Check essential knowledge Reinforce threat &amp; error management Reinforce significant airmanship points</li><li>Theory examination RPLA aeronautical knowledge examination (in-house) (in accordance with the knowledge standards specified in the Part 61 MOS) Knowledge deficiency report (required when the knowledge examination pass is less than 100%)</li><li>Pre-flight knowledge components complete: Instructor’s signature &amp; date</li></ul>',
    'casa-rpl-a-28',
    'RPL(A)28',
    'Consolidation',
    'flight',
    84,
